DO $deploy$
DECLARE v_lesson uuid;
BEGIN

  -- harvesting-the-rain/catching-water-before-its-lost
  VALUES ((SELECT id FROM courses WHERE slug = 'harvesting-the-rain'), 'catching-water-before-its-lost', $lj${"en":{"title":"Catching Water Before It's Lost","subtitle":"India's thousand-year-old answer to scarcity: catch the rain where it falls"},"hinglish":{"title":"Paani ko Khone se Pehle Pakadna","subtitle":"India ka hazaar-saal puraana jawaab scarcity ko: baarish ko wahin pakdo jahan woh girti hai","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Kya ho agar, ek poore rajya mein paani ghaseetne ke liye ek vishaal dam banane ke bajaaye, tum bas *baarish ko wahin pakad lo jahan woh girti hai*?\n\nIndia yahi kar raha hai — shaandaar tarike se — hazaaron saalon se.\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Ancient India mein **water harvesting** ki ek *anokhi* parampara thi.\n\nLog apne local **rainfall patterns** aur **soil types** ko gehrai se jaante the, aur rainwater, groundwater, river water — flood water tak — pakadne ke clever techniques bante, har ek local ecology ke hisaab se.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"**Pahaadon aur parvaton** mein, log diversion channels khodte the — Western Himalayas ke **guls** aur **kuls** — stream water ko apne kheton tak laane ke liye, farming ke liye.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"tutor_message","content":{"text":"**Bengal ke flood plains** mein, unhone **inundation channels** banaye taaki baadh khud unke kheton ko seenche.\n\nAur kai regions mein, **rooftop rainwater harvesting** peene ka paani pakadta aur store karta tha — khaaskar Rajasthan mein.\n","persona_id":"nova"},"xp_reward":0},{"order_index":5,"turn_type":"svg_graphic","content":{"title":"ALAG ZAMEEN, ALAG TAREEKE","caption":"Har region ne apni baarish aur soil ke hisaab se ek water-harvesting method banaya.","svg":"<svg viewBox=\"0 0 360 176\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"10\" y=\"8\" width=\"166\" height=\"76\" rx=\"6\" fill=\"#eff6ff\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"93\" y=\"28\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#1e3a8a\">Western Himalayas</text>\n  <text x=\"93\" y=\"50\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">guls and kuls —</text>\n  <text x=\"93\" y=\"64\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">diversion channels</text>\n  <rect x=\"184\" y=\"8\" width=\"166\" height=\"76\" rx=\"6\" fill=\"#ecfeff\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"267\" y=\"28\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#0e7490\">Bengal flood plains</text>\n  <text x=\"267\" y=\"50\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">inundation channels —</text>\n  <text x=\"267\" y=\"64\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">floods irrigate fields</text>\n  <rect x=\"10\" y=\"92\" width=\"166\" height=\"76\" rx=\"6\" fill=\"#fffbeb\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"93\" y=\"112\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#92400e\">Jaisalmer (arid)</text>\n  <text x=\"93\" y=\"134\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">khadins — fields turned</text>\n  <text x=\"93\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">into rain-fed stores</text>\n  <rect x=\"184\" y=\"92\" width=\"166\" height=\"76\" rx=\"6\" fill=\"#fff7ed\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"267\" y=\"112\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#9a3412\">Rajasthan</text>\n  <text x=\"267\" y=\"134\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">johads + rooftop</text>\n  <text x=\"267\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">harvesting</text>\n</svg>\n"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"**Arid aur semi-arid** regions mein, poore khet rain-fed storage mein badle gaye — paani ko *khada* rehne aur soil mein soakne dete hue use moist karne ko.\n\nJaisalmer ke **khadins** aur Rajasthan ke baaki hisson ke **johads** theek yahi karte hain: durlabh baarish ko pakdo, aur zameen se use rok do.\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"html_animation","content":{"title":"JAHAN GIRE WAHIN PAKDO","caption":"Baarish ko bah jaane dene ke bajaaye, ek chhota local structure use pakadta aur rakhta hai.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoRain { 0%{transform:translateY(-30px);opacity:0} 20%{opacity:1} 70%{transform:translateY(40px);opacity:1} 75%,100%{opacity:0} }\n    @keyframes geoStore { 0%,40%{height:2px} 75%,100%{height:26px} }\n    .geo-rd { animation: geoRain 3s linear infinite; }\n    .geo-rd2 { animation: geoRain 3s linear infinite; animation-delay:1s; }\n    .geo-store { animation: geoStore 3s ease-in infinite; }\n  </style>\n  <svg viewBox=\"0 0 240 120\" style=\"max-width:240px;width:100%\" font-family=\"sans-serif\">\n    <line class=\"geo-rd\" x1=\"100\" y1=\"20\" x2=\"100\" y2=\"34\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n    <line class=\"geo-rd2\" x1=\"140\" y1=\"20\" x2=\"140\" y2=\"34\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n    <path d=\"M70,92 Q120,70 170,92 L170,100 L70,100 Z\" fill=\"none\" stroke=\"#92400e\" stroke-width=\"2\"/>\n    <rect class=\"geo-store\" x=\"72\" y=\"72\" width=\"96\" height=\"26\" fill=\"#38bdf8\"/>\n    <text x=\"120\" y=\"114\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0369a1\">the rain is caught and held</text>\n  </svg>\n</div>\n"},"xp_reward":0},{"order_index":8,"turn_type":"tutor_message","content":{"text":"Yahan poora philosophy gaur karo.\n\nKoi vishaal dam nahi. Kisi padosi rajya se koi jhagda nahi. Bas *local* knowledge, *local* baarish pakadna, *local* needs ke liye.\n\nChhota, samajhdaar, aur bahut-bahut puraana.\n","persona_id":"nova"},"xp_reward":0},{"order_index":9,"turn_type":"mcq","content":{"question":"Western Himalayas ke 'guls' aur 'kuls' kya hain?","options":[{"id":"a","text":"Bijli ke liye bade multi-purpose dams.","is_correct":false,"rationale":"Yeh chhote traditional channels hain, bade dams nahi — ulta scale."},{"id":"b","text":"Diversion channels jo stream water ko kheton tak farming ke liye laate hain.","is_correct":true,"rationale":"Sahi — guls aur kuls pahaadi diversion channels hain, ek local water-harvesting method."},{"id":"c","text":"Peene ka paani store karne ke underground tanks.","is_correct":false,"rationale":"Yeh Rajasthan ke tankas hain, Himalayan guls aur kuls nahi."},{"id":"d","text":"Baarish pakadne ke rooftop pipes.","is_correct":false,"rationale":"Woh rooftop harvesting hai. Guls aur kuls stream water ke diversion channels hain."}],"xp":10},"xp_reward":10},{"order_index":10,"turn_type":"tap_to_match","content":{"prompt":"Har harvesting method ko uske region se match karo.","left":[{"id":"l1","label":"Guls aur kuls"},{"id":"l2","label":"Inundation channels"},{"id":"l3","label":"Khadins"},{"id":"l4","label":"Johads"}],"right":[{"id":"r1","label":"Western Himalayas"},{"id":"r2","label":"Bengal ke flood plains"},{"id":"r3","label":"Jaisalmer"},{"id":"r4","label":"Rajasthan ke baaki hisse"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":11,"turn_type":"exercise","content":{"instruction":"Apni locality ke aas-paas dekho. Kya kisi tareeke se rainwater pakda aur store hota hai — ek tank, talaab, rooftop collection pipe, check dam, ya baoli (stepwell)?\n\nPaper pe jo mile woh likho (ya jo banaaya ja *sake*). Neeche apne paas ek rainwater-harvesting structure type karo.\n","tool":"pencil","placeholder":"Mere paas, rainwater (ya pakda ja sakta) ___ se..."},"xp_reward":15},{"order_index":12,"turn_type":"fill_in_the_blank","content":{"prompt":"Do traditional methods ko lock karo.","template":"Western Himalayas mein, diversion channels jinhe {{blank-1}} ya kuls kehte hain paani ko kheton tak laate hain; Jaisalmer mein, khet rain-fed stores mein badle jaate hain jinhe {{blank-2}} kehte hain.\n","answers":[{"id":"blank-1","accepted":["guls","gul","Guls"]},{"id":"blank-2","accepted":["khadins","khadin","Khadins"]}]},"xp_reward":10},{"order_index":13,"turn_type":"reflection","content":{"prompt":"Sadiyon tak, communities ne apni paani ki problems local knowledge se solve ki — koi engineers nahi, koi bade budgets nahi. Tumhe kya lagta hai itni wisdom kyun bhula di gayi? Kya humein use wapas laana chahiye?\n\nKoi sahi jawaab nahi.\n","placeholder":"Woh local wisdom isliye fika padi kyunki..."},"xp_reward":5},{"order_index":14,"turn_type":"checkpoint","content":{"title":"Tum India ke traditional baarish-pakadne ke tareekon ko region se naam de sakte ho.","summary":"Bade dams se bahut pehle, India apni baarish locally pakadta tha: Himalayas mein guls aur kuls, Bengal mein inundation channels, Jaisalmer mein khadins, Rajasthan mein johads — har ek apni zameen aur baarish ke hisaab se.\n\nInme se ek method itna refined ho gaya ki ek hi underground room mein ek saal ka peene ka paani rakh sakta tha. Thar ke registan mein, rooftop aur *tanka* ne durlabh baarish ko ek lifeline mein badal diya. Yahi agli lesson hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 1, 11, 100, 'ai_chat', true)
  ON CONFLICT (course_id, slug) DO UPDATE SET
    translations = excluded.translations,
    order_index = excluded.order_index,
    estimated_minutes = excluded.estimated_minutes,
    xp_reward = excluded.xp_reward,
    format = 'ai_chat',
    is_published = true
  RETURNING id INTO v_lesson;
  DELETE FROM lesson_turns WHERE lesson_id = v_lesson;

  -- harvesting-the-rain/the-tankas-of-the-thar
  VALUES ((SELECT id FROM courses WHERE slug = 'harvesting-the-rain'), 'the-tankas-of-the-thar', $lj${"en":{"title":"The Tankas of the Thar","subtitle":"A room-sized hole in the ground, full of rain — a desert family's most precious thing"},"hinglish":{"title":"Thar ke Tankas","subtitle":"Zameen mein ek kamre jitna gaddha, baarish se bhara — ek registani parivaar ki sabse keemti cheez","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Thar registan mein, ghar ki sabse keemti cheez aksar sona ya zameen nahi hoti thi.\n\nWoh zameen mein ek kamre jitna gaddha hoti thi — baarish se bhara rakha. Use **tanka** kehte the.\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Rajasthan bhar mein — Bikaner, Phalodi, Barmer mein — lagbhag *har* ghar mein parmpara se ek underground tank, ek **tanka**, peene ka paani store karne ko hota tha.\n\nKuch toh vishaal the. Phalodi mein ek **6.1 metre gehra, 4.27 metre lamba, aur 2.44 metre chauda** tha — ek chhota kamra, paani se bhara.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"Tanka ek clever **rooftop rainwater harvesting** system ka hissa tha.\n\nMain ghar ya aangan ke andar bana, woh **sloping roof** se ek pipe se juda hota tha. Baarish chhat pe girti hai, pipe se neeche behti hai, aur tanka ko underground bharti hai. Saral, aur shaandaar.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"svg_graphic","content":{"title":"ROOFTOP SE TANKA","caption":"Sloping roof pe baarish ek pipe se neeche ek kamre jitne underground tank mein behti hai.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <line x1=\"40\" y1=\"20\" x2=\"60\" y2=\"20\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n  <line x1=\"90\" y1=\"16\" x2=\"110\" y2=\"16\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n  <polygon points=\"40,60 180,30 180,60\" fill=\"#fca5a5\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"110\" y=\"52\" text-anchor=\"middle\" font-size=\"8\" fill=\"#7f1d1d\">sloping roof</text>\n  <rect x=\"40\" y=\"60\" width=\"140\" height=\"48\" fill=\"#fef3c7\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"110\" y=\"88\" text-anchor=\"middle\" font-size=\"8\" fill=\"#92400e\">house</text>\n  <line x1=\"178\" y1=\"34\" x2=\"178\" y2=\"120\" stroke=\"#475569\" stroke-width=\"4\"/>\n  <text x=\"196\" y=\"80\" font-size=\"8\" fill=\"#475569\">pipe</text>\n  <rect x=\"150\" y=\"120\" width=\"120\" height=\"48\" rx=\"4\" fill=\"#7dd3fc\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"210\" y=\"142\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#075985\">TANKA</text>\n  <text x=\"210\" y=\"156\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0c4a6e\">underground store</text>\n</svg>\n"},"xp_reward":0},{"order_index":5,"turn_type":"tutor_message","content":{"text":"Ek detail dikhaata hai woh kitne careful the.\n\nBaarish ka **pehla daur** *nahi* collect hota tha. Use chhaton aur pipes ki saari dhool dho dene diya jaata tha pehle. Sirf *baad* ke showers — ab saaf — tanka mein store hote.\n\nSabr se bana ek built-in filter.\n","persona_id":"nova"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"Itni mehnat kyun? Kyunki tanka us paani ko **agli baarish** tak rakhta tha — peene ke paani ka ek bharosemand source un bedardi garmiyon mein, jab har doosra source sookh jaata.\n\nIs rainwater ka unke paas ek naam tha: **palar pani** — *natural paani ka sabse shudh roop*.\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"Ek bonus bhi tha.\n\nKai gharon ne tanka ke *bilkul paas* ek underground room banaya. Thanda jama paani us room ko thanda rakhta — registan ki garmi ke khilaaf ek natural air-conditioner. Ek dhaancha, do tohfe.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"html_animation","content":{"title":"TANKA BHARTA HAI","caption":"Chhat pe baarish, pipe se neeche, tanka mein — ek saal ka peene ka paani, store.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoTankaRain { 0%{transform:translateY(-20px);opacity:0} 25%{opacity:1} 70%{transform:translateY(70px);opacity:1} 80%,100%{opacity:0} }\n    @keyframes geoTankaFill { 0%,30%{height:3px} 80%,100%{height:34px} }\n    .geo-tr{animation:geoTankaRain 3s linear infinite} .geo-tr2{animation:geoTankaRain 3s linear infinite;animation-delay:1.2s}\n    .geo-tf{animation:geoTankaFill 3s ease-in infinite}\n  </style>\n  <svg viewBox=\"0 0 240 130\" style=\"max-width:240px;width:100%\" font-family=\"sans-serif\">\n    <polygon points=\"30,40 130,20 130,40\" fill=\"#fca5a5\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n    <line class=\"geo-tr\" x1=\"70\" y1=\"6\" x2=\"70\" y2=\"18\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n    <line class=\"geo-tr2\" x1=\"100\" y1=\"6\" x2=\"100\" y2=\"18\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n    <line x1=\"128\" y1=\"24\" x2=\"128\" y2=\"80\" stroke=\"#475569\" stroke-width=\"4\"/>\n    <rect x=\"100\" y=\"80\" width=\"90\" height=\"40\" rx=\"4\" fill=\"none\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n    <rect class=\"geo-tf\" x=\"103\" y=\"86\" width=\"84\" height=\"34\" fill=\"#38bdf8\"/>\n    <text x=\"145\" y=\"128\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0369a1\">tanka filling underground</text>\n  </svg>\n</div>\n"},"xp_reward":0},{"order_index":9,"turn_type":"tutor_message","content":{"text":"Afsos, western Rajasthan mein yeh parampara fika pad rahi hai.\n\nPerennial **Indira Gandhi Canal** ab bharpoor paani laati hai, toh kam log apne tankas sambhaalte hain. Halaanki kuch abhi bhi karte hain — kyunki unhe nal ke paani ke swaad se *palar pani* ka swaad zyaada pasand hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":10,"turn_type":"mcq","content":{"question":"Baarish ka pehla daur jaan-boojh kar tanka mein collect kyun NAHI kiya jaata tha?","options":[{"id":"a","text":"Kyunki pehli baarish zehreeli hoti hai.","is_correct":false,"rationale":"Yeh zehreeli nahi hoti — bas gandi hoti hai. Use dhone ke liye mod-aa jaata tha, isliye nahi ki woh toxic hai."},{"id":"b","text":"Taaki woh pehle chhaton aur pipes ki dhool dho de, taaki sirf saaf paani store ho.","is_correct":true,"rationale":"Bilkul — pehli baarish chhat aur pipe saaf karti hai; baad ke, saaf showers phir store hote hain."},{"id":"c","text":"Kyunki tanka hamesha pehle se bhara hota hai.","is_correct":false,"rationale":"Tanka sookhe mahinon mein khaali hota hai — harvesting ka poora point use dobaara bharna hai."},{"id":"d","text":"Kyunki pehli baarish turant vaashpit ho jaati hai.","is_correct":false,"rationale":"Woh turant vaashpit nahi hoti — use jaan-boojh kar system saaf karne ko mod-aa jaata hai."}],"xp":10},"xp_reward":10},{"order_index":11,"turn_type":"tap_to_match","content":{"prompt":"Har term ko uske matlab se match karo.","left":[{"id":"l1","label":"Tanka"},{"id":"l2","label":"Palar pani"},{"id":"l3","label":"Baarish ka pehla daur"},{"id":"l4","label":"Indira Gandhi Canal"}],"right":[{"id":"r1","label":"Peene ka paani store karne ka underground tank"},{"id":"r2","label":"Rainwater — sabse shudh natural paani"},{"id":"r3","label":"Chhat dhota hai; store nahi hota"},{"id":"r4","label":"Rooftop harvesting kyun ghat raha hai"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":12,"turn_type":"exercise","content":{"instruction":"*Apne* ghar ke liye ek saral rooftop-to-tank system sketch karo: baarish kahan girti hai, pipe kahan jaata hai, tank kahan baithta hai.\n\nPaper pe ek problem note karo jise tumhe solve karna padega (dhool? overflow? jagah?). Neeche apna sabse bada design challenge type karo.\n","tool":"pencil","placeholder":"Apne ghar pe baarish harvest karne ko, sabse mushkil hissa hoga..."},"xp_reward":15},{"order_index":13,"turn_type":"fill_in_the_blank","content":{"prompt":"Registan ke system ko lock karo.","template":"Rooftop ki baarish ek pipe se ek underground tank mein behti hai jise {{blank-1}} kehte hain; yeh rainwater, sabse shudh natural paani, {{blank-2}} pani kehlaata hai.\n","answers":[{"id":"blank-1","accepted":["tanka","Tanka","tank"]},{"id":"blank-2","accepted":["palar","Palar"]}]},"xp_reward":10},{"order_index":14,"turn_type":"reflection","content":{"prompt":"Jab canal aayi, logon ne ek aisa system sambhaalna chhod diya jo sadiyon se unki seva kar raha tha. Kya hamesha purane, self-reliant tareeke ko door se aane waale piped supply se badalna progress hai? Kya milta hai — aur kya khota hai?\n\nKoi sahi jawaab nahi.\n","placeholder":"Tanka ko canal se badalte hue, humne ___ paaya par khoya..."},"xp_reward":5},{"order_index":15,"turn_type":"checkpoint","content":{"title":"Tum samjha sakte ho ki Thar ka rooftop-aur-tanka system kaise kaam karta tha.","summary":"Rajasthan bhar mein, sloping roofs baarish ko pipes se kamre jitne underground tankas mein bhejte the — palar pani, sabse shudh paani, ko sookhi garmiyon bhar store karte hue, ek lagey room ko thanda tak rakhte hue. Pehli baarish system saaf karne ko qurbaan hoti thi. Sirf canal ne logon ko ise bhulaaya hai.\n\nPar yeh puraana idea mara nahi hai. Aaj India bhar mein, gaon aur poore rajya rainwater harvesting ko phir se zinda kar rahe hain — aur saabit kar rahe hain ki yeh abhi bhi shaandaar kaam karta hai. Yahi aakhri lesson hai, aur is chapter ka ant.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 2, 12, 100, 'ai_chat', true)
