  -- harvesting-the-rain/old-wisdom-working-today
  VALUES ((SELECT id FROM courses WHERE slug = 'harvesting-the-rain'), 'old-wisdom-working-today', $lj${"en":{"title":"Old Wisdom Working Today","subtitle":"A village 'rich in rainwater', a state that made harvesting the law"},"hinglish":{"title":"Purani Wisdom, Aaj Kaam Karti Hui","subtitle":"Ek gaon 'rainwater mein rich', ek rajya jisne harvesting ko kaanoon bana diya","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Ek gaon baarish pakadne mein itna achha ki use officially *\"rich in rainwater\"* kaha jaata hai. Ek rajya jisne baarish harvest karna **kaanoon** bana diya. Bamboo pipes 200 saal baad bhi fasal seench rahe.\n\nPurani wisdom koi museum ki cheez nahi. Yeh wapas hai — aur kaam kar rahi hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Aaj India bhar mein, traditional rainwater harvesting gharon, gaon, aur poore rajyon mein phir se zinda ho rahi hai — saabit karte hue ki yeh abhi bhi asli zaroortein poori kar sakti hai.\n\nChaar jagahein milte hain jahan yeh phal-phool rahi hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"Pehle, **Gendathur**, Mysuru, Karnataka ka ek door-daraaz gaon.\n\nLagbhag **200 households** ne rooftop rainwater harvesting lagaayi. Itna achha chala ki gaon ne ek durlabh khitaab kamaaya: woh *rainwater mein rich* ke roop mein jaana gaya.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"tutor_message","content":{"text":"Numbers yeh samjhaate hain.\n\nGendathur ko saal mein lagbhag **1,000 mm** baarish milti hai. Achhi rooftops aur saal mein lagbhag das fillings ke saath, har ghar lagbhag **50,000 litre** ikattha kar sakta hai — sirf apni chhat pe girne waali baarish se.\n","persona_id":"nova"},"xp_reward":0},{"order_index":5,"turn_type":"svg_graphic","content":{"title":"GENDATHUR KA RAINWATER GANIT","caption":"Saal mein 1,000 mm baarish, ek rooftop se pakdi, lagbhag 50,000 litre per house ban jaati hai.","svg":"<svg viewBox=\"0 0 360 160\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <line x1=\"40\" y1=\"16\" x2=\"56\" y2=\"16\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n  <line x1=\"80\" y1=\"12\" x2=\"96\" y2=\"12\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n  <line x1=\"120\" y1=\"16\" x2=\"136\" y2=\"16\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n  <text x=\"88\" y=\"40\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#0369a1\">1,000 mm rain / year</text>\n  <polygon points=\"40,76 150,52 150,76\" fill=\"#fca5a5\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <rect x=\"40\" y=\"76\" width=\"110\" height=\"36\" fill=\"#fef3c7\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"95\" y=\"98\" text-anchor=\"middle\" font-size=\"8\" fill=\"#92400e\">one rooftop</text>\n  <text x=\"200\" y=\"90\" font-size=\"18\" fill=\"#475569\">→</text>\n  <rect x=\"230\" y=\"58\" width=\"110\" height=\"70\" rx=\"6\" fill=\"#7dd3fc\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"285\" y=\"92\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"bold\" fill=\"#075985\">~50,000 L</text>\n  <text x=\"285\" y=\"108\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0c4a6e\">per house, per year</text>\n</svg>\n"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"Ab ek aisa vyang jo tum nahi bhuloge. **Shillong, Meghalaya** mein, rooftop harvesting sabse aam practice hai — *halaanki* paas ke **Cherrapunji** aur **Mawsynram** ko duniya ki **sabse zyaada baarish** milti hai.\n\nPhir bhi Shillong khud paani ki tez kami jhelta hai. Toh lagbhag har ghar baarish harvest karta hai, apne paani ka **15–25%** rooftop se leta hua. Earth ka sabse geela kona, phir bhi har boond pakadta hua.\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"Kuch jagahon ne ise official bana diya. **Tamil Nadu** **rooftop rainwater harvesting ko har ghar ke liye compulsory banane waala pehla Indian rajya** ban gaya — jo na maane unke liye legal punishment ke saath.\n\nBaarish harvest karna, kaanoon mein likh diya gaya.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"html_animation","content":{"title":"PUNARJEEVAN","caption":"Ek Karnataka gaon se ek Meghalaya capital tak ek rajya ke kaanoon tak — purani wisdom, phir se failti hui.","html":"<div style=\"background:#f0f9ff;padding:18px 14px;border-radius:12px;\">\n  <style>\n    @keyframes geoRev1 { 0%,5%{opacity:0;transform:translateY(8px)} 24%,100%{opacity:1;transform:none} }\n    @keyframes geoRev2 { 0%,30%{opacity:0;transform:translateY(8px)} 49%,100%{opacity:1;transform:none} }\n    @keyframes geoRev3 { 0%,55%{opacity:0;transform:translateY(8px)} 74%,100%{opacity:1;transform:none} }\n    .geo-rv{display:block;margin:5px 0;font:bold 11px sans-serif;color:#075985;background:#bae6fd;border-radius:6px;padding:6px 10px}\n    .grv1{animation:geoRev1 5s infinite} .grv2{animation:geoRev2 5s infinite} .grv3{animation:geoRev3 5s infinite}\n  </style>\n  <div class=\"geo-rv grv1\">Gendathur, Karnataka — \"rich in rainwater\"</div>\n  <div class=\"geo-rv grv2\">Shillong, Meghalaya — harvest despite the rain</div>\n  <div class=\"geo-rv grv3\">Tamil Nadu — harvesting made compulsory</div>\n</div>\n"},"xp_reward":0},{"order_index":9,"turn_type":"tutor_message","content":{"text":"Aur ek khoobsurat puraani technique abhi bhi **Meghalaya** mein chalti hai: **bamboo drip irrigation**, ek **200 saal puraana** system.\n\nBamboo pipes stream aur spring water tap karte hain. Lagbhag **18–20 litre** system mein ghusta hai, *sau metre* tak chalta hai, aur sirf **20–80 boondein per minute** ban ke pahunchta hai — har paudhe ki jadon tak seedhe. Ancient engineering, modern drip irrigation ki efficiency ke saath.\n","persona_id":"nova"},"xp_reward":0},{"order_index":10,"turn_type":"mcq","content":{"question":"Kaunsa pehla Indian rajya tha jisne rooftop rainwater harvesting ko sab gharon ke liye compulsory banaya?","options":[{"id":"a","text":"Rajasthan","is_correct":false,"rationale":"Rajasthan mein tankas ki sabse gehri parampara hai, par harvesting ko kaanoon se compulsory banane waala pehla woh nahi tha."},{"id":"b","text":"Tamil Nadu","is_correct":true,"rationale":"Sahi — Tamil Nadu rooftop rainwater harvesting ko compulsory banane waala pehla rajya tha, defaulters ke liye penalties ke saath."},{"id":"c","text":"Meghalaya","is_correct":false,"rationale":"Meghalaya mein Shillong ki rooftop harvesting aur bamboo drip irrigation hai, par statewide compulsory pehle nahi banaya."},{"id":"d","text":"Karnataka","is_correct":false,"rationale":"Karnataka mein Gendathur hai, 'rainwater mein rich' gaon — par Tamil Nadu pehle kaanoon laaya."}],"xp":10},"xp_reward":10},{"order_index":11,"turn_type":"tap_to_match","content":{"prompt":"Har jagah ya system ko uski pehchaan se match karo.","left":[{"id":"l1","label":"Gendathur (Karnataka)"},{"id":"l2","label":"Shillong (Meghalaya)"},{"id":"l3","label":"Tamil Nadu"},{"id":"l4","label":"Bamboo drip irrigation"}],"right":[{"id":"r1","label":"Gaon jo 'rich in rainwater' kehlaata hai"},{"id":"r2","label":"Paas sabse zyaada baarish ke bawajood harvest karta hai"},{"id":"r3","label":"Harvesting ko compulsory banane waala pehla rajya"},{"id":"r4","label":"Meghalaya mein 200 saal puraana bamboo-pipe system"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":12,"turn_type":"exercise","content":{"instruction":"Apni locality mein ya aas-paas ek aur rainwater-harvesting system dhundo — ya apne school ya ghar ke liye ek saral banaao.\n\nPaper pe batao paani kaise pakda, store, aur use hota hai. Neeche apna ek-line idea type karo.\n","tool":"pencil","placeholder":"Mere school/ghar ke liye ek harvesting system..."},"xp_reward":15},{"order_index":13,"turn_type":"fill_in_the_blank","content":{"prompt":"Modern revival ko lock karo.","template":"{{blank-1}} rooftop rainwater harvesting ko compulsory banane waala pehla Indian rajya tha; Meghalaya mein, {{blank-2}} pipes ek 200 saal puraane drip system mein spring water le jaate hain.\n","answers":[{"id":"blank-1","accepted":["Tamil Nadu","tamil nadu","TamilNadu"]},{"id":"blank-2","accepted":["bamboo","Bamboo","baans"]}]},"xp_reward":10},{"order_index":14,"turn_type":"reflection","content":{"prompt":"Is poore chapter mein — scarcity, dams, aur harvesting — paani ke baare mein woh ek idea kaunsa hai jo tum sach mein apne saath le jaaoge? Use naam do, aur batao kyun woh atak gaya.\n\nKoi sahi jawaab nahi. Yeh tumhara takeaway hai.\n","placeholder":"Jo idea main rakh raha hoon woh hai..."},"xp_reward":5},{"order_index":15,"turn_type":"checkpoint","content":{"title":"Poora chapter ab tumhara hai: scarcity, dams, aur baarish ka harvesting.","summary":"Gendathur ki rainwater-rich rooftops se Shillong ki zaroorat tak, Tamil Nadu ke kaanoon se Meghalaya ke 200 saal puraane bamboo pipes tak — India saabit kar raha hai ki purani paani wisdom abhi bhi kaam karti hai. Aur yahi chapter ko poora karta hai.\n\nTumne seekha ki paani renewable hai phir bhi scarce — demand se khaali hota, sirf sookhe se nahi, aur kabhi pollution se barbaad; tum multi-purpose dams (temples of modern India) ke vaade ko unki bhaari costs aur woh disputes jo woh chhedte hain ke saamne tol sakte ho; aur tumne sabse puraana, sabse chhota, sabse samajhdaar jawaab dekha — baarish ko wahin pakadna jahan woh girti hai.\n\nAgli baar jab baarish hogi, tum use alag dekhoge: mausam ki tarah nahi, balki ek resource ki tarah jo bhaag raha hai, pakde jaane ki guzaarish karta hua.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 3, 12, 100, 'ai_chat', true)
  ON CONFLICT (course_id, slug) DO UPDATE SET
    translations = excluded.translations,
    order_index = excluded.order_index,
    estimated_minutes = excluded.estimated_minutes,
    xp_reward = excluded.xp_reward,
    format = 'ai_chat',
    is_published = true
  RETURNING id INTO v_lesson;
  DELETE FROM lesson_turns WHERE lesson_id = v_lesson;

  -- multi-purpose-river-projects/dams-and-their-many-uses
  VALUES ((SELECT id FROM courses WHERE slug = 'multi-purpose-river-projects'), 'dams-and-their-many-uses', $lj${"en":{"title":"Dams and Their Many Uses","subtitle":"One wall across a river that lights cities, waters deserts, and stops floods"},"hinglish":{"title":"Dam aur Unke Anek Upyog","subtitle":"Ek nadi ke aar-paar ek deewar jo sheher jagaati, registan seenchti, aur baadh rokti","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Ek nadi ke aar-paar ek deewar banao, aur tum ek sheher jagaa sakte ho, ek registan seench sakte ho, ek baadh rok sakte ho, aur machhli paal sakte ho — sab ek hi saath.\n\nJaadu lagta hai. Yeh ek **dam** hai. Dekhte hain yeh ek saath itne kaam kaise karta hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"India yeh *hazaaron saal* se kar raha hai.\n\nSringaverapura ke paas **1st century BC** mein flood-water harvesting system tha. Chandragupta Maurya ke daur mein dams aur lakes bane. 11vi sadi ka **Bhopal Lake** aur Delhi ka **Hauz Khas** tank uske baad. Modern India ne bas ek puraani parampara jaari rakhi — concrete ke saath.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"Toh dam hai *kya*, theek-theek?\n\nBehte paani ke aar-paar ek **barrier** jo flow ko rokta, mod-ta, ya dheema karta hai — aam taur pe ek **reservoir** banata hai, uske peeche jama paani ki ek jheel. Zyaadatar dams mein ek **spillway** hota hai jo extra paani ko surakshit roop se bah jaane deta hai, taaki dam phoote na.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"media","content":{"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch03-water-resources/c2l1-dam.png","caption":"Ek multi-purpose dam: ek concrete deewar jo vishaal reservoir ko rokti hai, spillway se paani garajta hua.","aspect_ratio":1.7778},"xp_reward":0},{"order_index":5,"turn_type":"svg_graphic","content":{"title":"DAM KI BANAAWAT","caption":"Ek barrier reservoir rokta hai; spillway extra paani chhodta hai; nadi neeche aage behti hai.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"0\" y=\"60\" width=\"180\" height=\"100\" fill=\"#7dd3fc\"/>\n  <text x=\"80\" y=\"100\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#075985\">RESERVOIR</text>\n  <text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0c4a6e\">stored water</text>\n  <polygon points=\"180,60 220,60 210,160 180,160\" fill=\"#94a3b8\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"200\" y=\"120\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#1e293b\" transform=\"rotate(90 200 120)\">DAM</text>\n  <path d=\"M180,62 Q200,58 220,68 L222,82 Q200,72 184,80 Z\" fill=\"#38bdf8\"/>\n  <text x=\"240\" y=\"58\" font-size=\"8\" fill=\"#0369a1\">spillway</text>\n  <line x1=\"225\" y1=\"70\" x2=\"232\" y2=\"58\" stroke=\"#0369a1\" stroke-width=\"1\"/>\n  <rect x=\"210\" y=\"140\" width=\"150\" height=\"20\" fill=\"#7dd3fc\"/>\n  <text x=\"290\" y=\"154\" text-anchor=\"middle\" font-size=\"8\" fill=\"#075985\">river continues</text>\n</svg>\n"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"Dams pehle sirf *ek* kaam ke liye bante the: irrigation — baad mein kheton ko seenchne ke liye rainwater store karna.\n\nAaj woh **multi-purpose** hain — ek dam, kayi kaam ek saath:\n\n- irrigation\n- bijli (**hydel power**)\n- ghar aur industry ke liye water supply\n- flood control\n- recreation, inland navigation, aur fish breeding\n\nNadiyon ka Swiss Army knife.\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"Do mashhoor examples idea dikhaate hain.\n\n**Bhakra-Nangal**, Sutlej-Beas pe, *dono* hydel power *aur* irrigation ke liye use hota hai. **Hirakud**, Mahanadi pe, water *conservation* ko *flood control* ke saath jodta hai.\n\nHar ek mein, jama paani ke kayi uses ek-doosre se gunde hain — yahi \"integrated\" ka matlab hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"html_animation","content":{"title":"EK DAM, KAYI KAAM","caption":"Power, crops, peene ka paani, machhli, flood control — sab ek hi project se.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoJob1 { 0%,5%{opacity:.15} 20%,100%{opacity:1} }\n    @keyframes geoJob2 { 0%,25%{opacity:.15} 40%,100%{opacity:1} }\n    @keyframes geoJob3 { 0%,45%{opacity:.15} 60%,100%{opacity:1} }\n    @keyframes geoJob4 { 0%,65%{opacity:.15} 80%,100%{opacity:1} }\n    .geo-j { display:inline-block; margin:4px; padding:6px 12px; border-radius:999px; font:bold 11px sans-serif; color:#fff; }\n    .gj1{background:#ca8a04;animation:geoJob1 5s infinite} .gj2{background:#16a34a;animation:geoJob2 5s infinite}\n    .gj3{background:#0891b2;animation:geoJob3 5s infinite} .gj4{background:#7c3aed;animation:geoJob4 5s infinite}\n  </style>\n  <div style=\"font:bold 20px sans-serif;color:#075985;margin-bottom:8px\">one dam</div>\n  <span class=\"geo-j gj1\">electricity</span><span class=\"geo-j gj2\">irrigation</span><span class=\"geo-j gj3\">water supply</span><span class=\"geo-j gj4\">flood control</span>\n</div>\n"},"xp_reward":0},{"order_index":9,"turn_type":"tutor_message","content":{"text":"Jawaharlal Nehru ne garv se dams ko **\"temples of modern India\"** kaha.\n\nKyun *temples*? Kyunki unhone inhe kheti aur village economy ko tezi se industrialisation aur urban growth ke saath bunte dekha — ek naye azaad desh ko uske colonial past se uthaane ka engine.\n","persona_id":"nova"},"xp_reward":0},{"order_index":10,"turn_type":"mcq","content":{"question":"Ek dam ko 'multi-purpose' project kya banata hai?","options":[{"id":"a","text":"Yeh ek aam dam se oonchaa hai.","is_correct":false,"rationale":"Oonchaai dams ko classify karti hai, par 'multi-purpose' *uses* ke baare mein hai, size ke nahi."},{"id":"b","text":"Iska jama paani ek saath kayi integrated uses serve karta hai — irrigation, power, supply, flood control, aur zyaada.","is_correct":true,"rationale":"Bilkul. Ek multi-purpose dam ek hi impounded paani ke kayi uses ko ek saath bunta hai."},{"id":"c","text":"Yeh kayi alag rajya milke banate hain.","is_correct":false,"rationale":"Kaun banata hai woh point nahi — 'multi-purpose' un kaiyon ko bataata hai jo dam *karta* hai."},{"id":"d","text":"Yeh sirf bijli banane ke liye use hota hai.","is_correct":false,"rationale":"Woh single-purpose hota. Multi-purpose ka matlab kayi uses milaa ke."}],"xp":10},"xp_reward":10},{"order_index":11,"turn_type":"tap_to_match","content":{"prompt":"Har term ko us se match karo jo woh hai.","left":[{"id":"l1","label":"Bhakra-Nangal"},{"id":"l2","label":"Hirakud"},{"id":"l3","label":"Spillway"},{"id":"l4","label":"Reservoir"}],"right":[{"id":"r1","label":"Hydel power plus irrigation (Sutlej-Beas)"},{"id":"r2","label":"Water conservation plus flood control (Mahanadi)"},{"id":"r3","label":"Extra paani ko surakshit bah jaane deta hai"},{"id":"r4","label":"Dam ke peeche jama paani ki jheel"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":12,"turn_type":"exercise","content":{"instruction":"Apne region ke baare mein socho. Agar ek multi-purpose dam use serve karta, toh uske kaunse uses sabse zyaada maayne rakhte — bijli, irrigation, peene ka paani, ya flood control?\n\nPaper pe apne top do rank karo aur batao kyun. Neeche apna number-one use type karo.\n","tool":"pencil","placeholder":"Mere region ke liye, sabse zaroori use hoga..."},"xp_reward":15},{"order_index":13,"turn_type":"fill_in_the_blank","content":{"prompt":"Basics ko lock karo.","template":"Ek dam jama paani ki ek jheel rokta hai jise {{blank-1}} kehte hain, aur Nehru ne dams ko temples of modern {{blank-2}} kaha.\n","answers":[{"id":"blank-1","accepted":["reservoir","Reservoir"]},{"id":"blank-2","accepted":["India","india"]}]},"xp_reward":10},{"order_index":14,"turn_type":"reflection","content":{"prompt":"Nehru ne dams ko *temples* kaha — pragati ke lagbhag pavitra prateek. Tumhe kya lagta hai ek naye desh ko aise symbols ki zaroorat kyun thi, sirf useful structures ki nahi?\n\nKoi sahi jawaab nahi.\n","placeholder":"Ek naye desh ko symbols isliye chahiye the kyunki..."},"xp_reward":5},{"order_index":15,"turn_type":"checkpoint","content":{"title":"Tum samjha sakte ho ki multi-purpose dam kya hai aur use kyun manaya gaya.","summary":"Dam ek barrier hai jo paani ko reservoir mein store karta hai; ek multi-purpose project irrigation, power, water supply, flood control, aur zyaada ko ek saath bunta hai — jaise Bhakra-Nangal aur Hirakud. Nehru ne inhe temples of modern India bataya.\n\nPar har temple ki ek keemat hoti hai. Samay ke saath, in vishaal projects pe teekhi aalochna aayi — woh nadiyon, zameen, aur logon ke saath jo karte hain uske liye. Ek bade dam ki chhupi keemat kya hai? Yahi agli lesson hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 1, 12, 100, 'ai_chat', true)
  ON CONFLICT (course_id, slug) DO UPDATE SET
    translations = excluded.translations,
    order_index = excluded.order_index,
    estimated_minutes = excluded.estimated_minutes,
    xp_reward = excluded.xp_reward,
