  -- multi-purpose-river-projects/when-dams-do-harm
  VALUES ((SELECT id FROM courses WHERE slug = 'multi-purpose-river-projects'), 'when-dams-do-harm', $lj${"en":{"title":"When Dams Do Harm","subtitle":"The structures built to stop floods sometimes cause them"},"hinglish":{"title":"Jab Dam Nuksaan Karte Hain","subtitle":"Jo dhaanche baadh rokne ko bane, unhone kabhi-kabhi baadh laayi","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Yeh raha is lesson ka bedardi vyang: baadh *rokne* ko bane dams ne kabhi-kabhi baadh *laayi* hai.\n\nTemple apne pujaariyon pe palat gaya. Dekhte hain ki itna useful dhaancha itna nuksaan kaise kar sakta hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Yeh ek baat se shuru hota hai: ek nadi ko damming karke, tum uska **natural flow** badal dete ho. Aur yeh ek badlaav ek poori shrinkhala chhed deta hai.\n\nShuru karo nadi jo le jaati hai us se — sediment.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"Ek free-behti nadi **sediment** (silt) neeche le jaati hai. Use dam karo, aur woh silt reservoir ke neeche baith jaati hai — **excessive sedimentation** — jabki dam ke *neeche* ki nadi sediment-starved behti hai.\n\nNeeche nateeja: **rockier streambeds** aur nadi ke aquatic jeevan ke liye poorer habitats.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"tutor_message","content":{"text":"Dams nadiyon ko **fragment** bhi karte hain — woh deewarein hain. Machhli aur doosre aquatic fauna inke aar-paar migrate nahi kar sakte, jo tab jaanleva hai jab unhe **spawn** karne upstream jaana ho.\n\nAur reservoir floodplain ko doobota hai, **submerging** vegetation aur soil jo phir dheere-dheere paani ke neeche sad jaate hain.\n","persona_id":"nova"},"xp_reward":0},{"order_index":5,"turn_type":"media","content":{"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch03-water-resources/c2l2-displaced-village.png","caption":"Jab reservoir bharta hai, poore gaon doob jaate hain — chhaton ke upar paani, parivaar oonchi zameen pe jaate hue. Ek bade dam ki insaani keemat.","aspect_ratio":1.7778},"xp_reward":0},{"order_index":6,"turn_type":"svg_graphic","content":{"title":"FREE NADI vs DAMMED NADI","caption":"Ek free nadi silt failaati aur machhli ko migrate karne deti hai; ek dam silt ko phasaata aur machhli ko rokta hai.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <text x=\"10\" y=\"22\" font-size=\"9\" font-weight=\"bold\" fill=\"#166534\">Free river</text>\n  <rect x=\"10\" y=\"28\" width=\"340\" height=\"22\" fill=\"#7dd3fc\"/>\n  <circle cx=\"60\" cy=\"39\" r=\"3\" fill=\"#a16207\"/><circle cx=\"120\" cy=\"39\" r=\"3\" fill=\"#a16207\"/><circle cx=\"200\" cy=\"39\" r=\"3\" fill=\"#a16207\"/><circle cx=\"290\" cy=\"39\" r=\"3\" fill=\"#a16207\"/>\n  <text x=\"300\" y=\"64\" text-anchor=\"middle\" font-size=\"7\" fill=\"#166534\">silt + fish move freely →</text>\n  <text x=\"10\" y=\"100\" font-size=\"9\" font-weight=\"bold\" fill=\"#991b1b\">Dammed river</text>\n  <rect x=\"10\" y=\"106\" width=\"150\" height=\"22\" fill=\"#38bdf8\"/>\n  <circle cx=\"40\" cy=\"117\" r=\"3\" fill=\"#a16207\"/><circle cx=\"80\" cy=\"117\" r=\"3\" fill=\"#a16207\"/><circle cx=\"130\" cy=\"117\" r=\"3\" fill=\"#a16207\"/>\n  <polygon points=\"160,98 178,98 172,150 160,150\" fill=\"#94a3b8\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <rect x=\"178\" y=\"116\" width=\"172\" height=\"12\" fill=\"#7dd3fc\"/>\n  <text x=\"85\" y=\"144\" text-anchor=\"middle\" font-size=\"7\" fill=\"#991b1b\">silt trapped, fish blocked</text>\n  <text x=\"264\" y=\"144\" text-anchor=\"middle\" font-size=\"7\" fill=\"#991b1b\">rocky, starved streambed</text>\n</svg>\n"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"Aur bigadta hai.\n\nReservoirs **earthquakes induce** kar sakte hain, **water-borne diseases** aur pests paida kar sakte hain, aur over-use se pollution. Aur bedardi se, baadh *control* karne ko bane dams ne kabhi-kabhi *baadh laayi* hai — sedimentation reservoir bhar deti hai, aur bhaari baarish mein bade dams aksar baadh ko bilkul rok hi nahi paate.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"tutor_message","content":{"text":"Ek farming ka dank bhi hai.\n\nNeeche ki floodplains apni saalana **silt** ki parat khoti hain — ek muft natural fertiliser — jo land degradation badhata hai. Aur irrigation kisaanon ko **water-intensive, commercial crops** ki taraf dhakelti hai, jo samay ke saath soil ko **salinise** kar deti hain (namak jam ke use zehreela kar deta hai).\n","persona_id":"nova"},"xp_reward":0},{"order_index":9,"turn_type":"tutor_message","content":{"text":"Aur sabse bhaari keemat insaani hai.\n\nBade dams poore gaon aur khet doobote hain, **large-scale displacement aur loss of livelihood** karte hue. Narmada pe **Sardar Sarovar** dam is sangharsh ka prateek ban gaya.\n\n(Baadh-prone **Damodar** ko bahut samay tak *\"river of sorrow\"* kaha gaya.)\n","persona_id":"nova"},"xp_reward":0},{"order_index":10,"turn_type":"html_animation","content":{"title":"CHHUPI KEEMATEIN","caption":"Phasi silt, ruki machhli, namkeen soil, visthaapit ghar — woh bill jo ek bada dam chadhaata hai.","html":"<div style=\"background:#fff7ed;padding:18px 14px;border-radius:12px;\">\n  <style>\n    @keyframes geoCost1 { 0%,5%{opacity:0;transform:translateX(-10px)} 24%,100%{opacity:1;transform:none} }\n    @keyframes geoCost2 { 0%,28%{opacity:0;transform:translateX(-10px)} 47%,100%{opacity:1;transform:none} }\n    @keyframes geoCost3 { 0%,51%{opacity:0;transform:translateX(-10px)} 70%,100%{opacity:1;transform:none} }\n    @keyframes geoCost4 { 0%,74%{opacity:0;transform:translateX(-10px)} 92%,100%{opacity:1;transform:none} }\n    .geo-c{display:block;margin:5px 0;font:bold 11px sans-serif;color:#7c2d12;background:#fed7aa;border-radius:6px;padding:6px 10px}\n    .gc1{animation:geoCost1 5s infinite} .gc2{animation:geoCost2 5s infinite} .gc3{animation:geoCost3 5s infinite} .gc4{animation:geoCost4 5s infinite}\n  </style>\n  <div class=\"geo-c gc1\">Silt trapped → poorer soil & aquatic life</div>\n  <div class=\"geo-c gc2\">Rivers fragmented → fish can't migrate</div>\n  <div class=\"geo-c gc3\">Soil salinised by water-intensive crops</div>\n  <div class=\"geo-c gc4\">Villages submerged → people displaced</div>\n</div>\n"},"xp_reward":0},{"order_index":11,"turn_type":"mcq","content":{"question":"Inme se kaunsa multi-purpose river projects ke *paksh* mein ek tark NAHI hai?","options":[{"id":"a","text":"Woh un ilaaqon mein paani laate hain jo water scarcity jhelte hain.","is_correct":false,"rationale":"Yeh unke paksh mein hai — scarce ilaaqon ko paani dena ek key benefit hai."},{"id":"b","text":"Water flow regulate karke, woh baadh control mein madad karte hain.","is_correct":false,"rationale":"Yeh ek benefit hai (theory mein) — flood control unke stated purposes mein se ek hai."},{"id":"c","text":"Woh large-scale displacement aur loss of livelihood karte hain.","is_correct":true,"rationale":"Sahi — yeh ek *cost* hai, bade dams ke *khilaaf* ek tark, paksh mein nahi."},{"id":"d","text":"Woh humare industries aur ghar ke liye bijli banate hain.","is_correct":false,"rationale":"Yeh ek benefit hai — hydel power dams banane ki ek mukhya wajah hai."}],"xp":10},"xp_reward":10},{"order_index":12,"turn_type":"tap_to_match","content":{"prompt":"Har nuksaan ko us se match karo jo use karta hai.","left":[{"id":"l1","label":"Excessive sedimentation"},{"id":"l2","label":"Machhli spawn karne migrate nahi kar sakti"},{"id":"l3","label":"Soil salinisation"},{"id":"l4","label":"Logon ka displacement"}],"right":[{"id":"r1","label":"Silt aage behne ke bajaaye reservoir mein baith jaati hai"},{"id":"r2","label":"Dam ek deewar se nadi ko fragment karta hai"},{"id":"r3","label":"Water-intensive commercial crops ki taraf shift"},{"id":"r4","label":"Reservoir gaon aur khet doobota hai"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":13,"turn_type":"exercise","content":{"instruction":"Kisi dam ya reservoir ke baare mein socho jiske baare mein tumne suna ho (Sardar Sarovar, Bhakra-Nangal, ya koi local).\n\nPaper pe uska ek saaf *benefit* aur ek saaf *cost* likho. Neeche dam ka naam aur uski sabse badi cost type karo.\n","tool":"pencil","placeholder":"___ dam — iski sabse badi cost hai..."},"xp_reward":15},{"order_index":14,"turn_type":"fill_in_the_blank","content":{"prompt":"Do badi costs ko lock karo.","template":"Ek nadi ko damming karne se {{blank-1}} reservoir mein phas jaati hai aage behne ke bajaaye, aur gaon doobne se logon ko {{blank-2}} mein dhakela jaata hai.\n","answers":[{"id":"blank-1","accepted":["silt","sediment","Silt"]},{"id":"blank-2","accepted":["displacement","Displacement","visthaapan"]}]},"xp_reward":10},{"order_index":15,"turn_type":"reflection","content":{"prompt":"Ek dam das lakh ghar jagaa sakta hai — aur kuch hazaar gaon waalon ke ghar dubo sakta hai. Ek desh ko kaiyon ke fayde ko kuch logon ki bhaari keemat ke saamne kaise tolna chahiye? Imaandaar raho ki yeh kitna mushkil hai.\n\nKoi sahi jawaab nahi.\n","placeholder":"Kaiyon ko kuch ke saamne tolte hue, mujhe lagta hai..."},"xp_reward":5},{"order_index":16,"turn_type":"checkpoint","content":{"title":"Tum bade dams ki asli costs ko unke benefits ke saamne tol sakte ho.","summary":"Ek nadi ko damming silt ko phasaata hai, habitats ko starve aur fragment karta hai, soil ko salinise karta hai, quakes induce aur baadh tak bigaad sakta hai — aur sabse mushkil, poore samudaayon ko visthaapit karta hai, jaisa Narmada sangharsh ne dikhaya.\n\nAur bade projects ek aur takraav paida karte hain: jab ek hi nadi kayi rajyon se behti hai, *paani kise mile?* Hum ek nadi fairly kaise baantein? Yahi agli lesson hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 2, 12, 100, 'ai_chat', true)
  ON CONFLICT (course_id, slug) DO UPDATE SET
    translations = excluded.translations,
    order_index = excluded.order_index,
    estimated_minutes = excluded.estimated_minutes,
