  -- multi-purpose-river-projects/sharing-water-wisely
  VALUES ((SELECT id FROM courses WHERE slug = 'multi-purpose-river-projects'), 'sharing-water-wisely', $lj${"en":{"title":"Sharing Water Wisely","subtitle":"A river doesn't stop at a state border — so who owns the water?"},"hinglish":{"title":"Paani Samajhdaari se Baantna","subtitle":"Ek nadi rajya ki seema pe nahi rukti — toh paani kiska?","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Ek nadi ko rajya ki seemaon ki parwah nahi. Woh bas behti hai.\n\nToh jab ek nadi paanch rajyon se behti hai, yeh awkward sawaal koi taal nahi sakta: *paani kiska?*\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Ek hi nadi aksar *kayi* rajyon se guzarti hai, aur har ek apna hissa chahta hai. Pench: jab ek upstream rajya zyaada leta hai, har downstream rajya ko **kam** milta hai.\n\nUs tanaav ka ek naam hai — **inter-state water disputes**.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"**Krishna-Godavari dispute** lo.\n\nMaharashtra **Koyna** pe ek multi-purpose project ke liye zyaada paani divert karna chahta tha. Par usse Karnataka aur Andhra Pradesh mein **downstream flow** ghat jaata — *unki* agriculture aur industry ko nuksaan. Toh in do rajyon ne aapatti jatayi.\n\nEk nadi, teen sarkaarein, ek jhagda.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"svg_graphic","content":{"title":"EK NADI, TEEN RAJYA","caption":"Upstream zyaada paani lo, aur downstream rajyon tak kam pahunchta hai — dispute ki jad.","svg":"<svg viewBox=\"0 0 360 170\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <polygon points=\"20,60 130,60 130,84 20,96\" fill=\"#38bdf8\"/>\n  <polygon points=\"130,62 240,66 240,82 130,82\" fill=\"#7dd3fc\"/>\n  <polygon points=\"240,68 340,72 340,80 240,80\" fill=\"#bae6fd\"/>\n  <polygon points=\"120,52 138,52 134,96 120,96\" fill=\"#94a3b8\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"129\" y=\"46\" text-anchor=\"middle\" font-size=\"7\" fill=\"#475569\">diversion</text>\n  <text x=\"70\" y=\"120\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#075985\">Upstream</text>\n  <text x=\"70\" y=\"132\" text-anchor=\"middle\" font-size=\"7\" fill=\"#166534\">takes more →</text>\n  <text x=\"185\" y=\"120\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#0369a1\">Midstream</text>\n  <text x=\"185\" y=\"132\" text-anchor=\"middle\" font-size=\"7\" fill=\"#854d0e\">less arrives</text>\n  <text x=\"295\" y=\"120\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#1e3a8a\">Downstream</text>\n  <text x=\"295\" y=\"132\" text-anchor=\"middle\" font-size=\"7\" fill=\"#991b1b\">least of all</text>\n</svg>\n"},"xp_reward":0},{"order_index":5,"turn_type":"tutor_message","content":{"text":"Aise disputes hi wajah hain ki humein **integrated water resources management** chahiye — ek nadi ke *poore basin* ko ek saath plan karna, rajya-dar-rajya nahi.\n\nBasin ko ek system ki tarah manage karo, aur kayi uses aur kayi users *balance* ho sakte hain, har boond pe ladne ke bajaaye.\n","persona_id":"nova"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"Farming ki taraf, **Pradhan Mantri Krishi Sinchayee Yojana (PMKSY)** har khet ko *protective irrigation* dena chahti hai. Do slogans ise pakadte hain:\n\n- *\"har khet ko pani\"* — har khet ko paani\n- *\"per drop more crop\"* — kam paani se zyaada fasal\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"PMKSY ke goals in slogans se nikalte hain: *assured* irrigation ke neeche area badhaao, on-farm paani-use **efficiency** sudhaaro taaki barbaadi ghate, aur *sustainable conservation* practices banaao.\n\nKam use karo, zyaada ugaao, fairly baanto. Yahi poora philosophy ek line mein.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"html_animation","content":{"title":"EK NADI, KAYI PADOSI","caption":"Jab upstream bucket pehle bharta hai, downstream buckets neeche reh jaate hain.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoUp { 0%,10%{height:6px} 50%,100%{height:34px} }\n    @keyframes geoMid { 0%,30%{height:4px} 70%,100%{height:20px} }\n    @keyframes geoLow { 0%,50%{height:3px} 90%,100%{height:10px} }\n    .geo-up{animation:geoUp 5s ease-in-out infinite alternate} .geo-mid{animation:geoMid 5s ease-in-out infinite alternate} .geo-low{animation:geoLow 5s ease-in-out infinite alternate}\n  </style>\n  <svg viewBox=\"0 0 300 100\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <rect x=\"40\" y=\"20\" width=\"50\" height=\"60\" rx=\"4\" fill=\"none\" stroke=\"#475569\" stroke-width=\"2\"/>\n    <rect class=\"geo-up\" x=\"44\" y=\"46\" width=\"42\" height=\"34\" fill=\"#0ea5e9\"/>\n    <rect x=\"125\" y=\"20\" width=\"50\" height=\"60\" rx=\"4\" fill=\"none\" stroke=\"#475569\" stroke-width=\"2\"/>\n    <rect class=\"geo-mid\" x=\"129\" y=\"60\" width=\"42\" height=\"20\" fill=\"#38bdf8\"/>\n    <rect x=\"210\" y=\"20\" width=\"50\" height=\"60\" rx=\"4\" fill=\"none\" stroke=\"#475569\" stroke-width=\"2\"/>\n    <rect class=\"geo-low\" x=\"214\" y=\"70\" width=\"42\" height=\"10\" fill=\"#7dd3fc\"/>\n    <text x=\"65\" y=\"94\" text-anchor=\"middle\" font-size=\"7\" fill=\"#075985\">upstream</text>\n    <text x=\"150\" y=\"94\" text-anchor=\"middle\" font-size=\"7\" fill=\"#0369a1\">midstream</text>\n    <text x=\"235\" y=\"94\" text-anchor=\"middle\" font-size=\"7\" fill=\"#1e3a8a\">downstream</text>\n  </svg>\n</div>\n"},"xp_reward":0},{"order_index":9,"turn_type":"mcq","content":{"question":"Krishna-Godavari dispute jaise inter-state water disputes kyun uthte hain?","options":[{"id":"a","text":"Kyunki nadiyaan rajya ki seemaon pe poori tarah sookh jaati hain.","is_correct":false,"rationale":"Nadiyaan seemaon ke aar-paar aazaadi se behti hain — wahan sookhti nahi. Dispute is baare mein hai ki shared flow kaise bata hai."},{"id":"b","text":"Kyunki ek nadi kayi rajyon se guzarti hai, aur ek upstream rajya zyaada paani lekar downstream waalon ke liye kam chhodta hai.","is_correct":true,"rationale":"Bilkul. Upstream diversion (jaise Maharashtra Koyna pe) Karnataka aur Andhra Pradesh mein downstream flow ghataata hai."},{"id":"c","text":"Kyunki har rajya apni alag nadi banata hai.","is_correct":false,"rationale":"Rajya *ek hi* nadi share karte hain — yahi poori problem hai. Har ek alag nahi rakh sakta."},{"id":"d","text":"Kyunki downstream rajya bilkul paani use nahi karte.","is_correct":false,"rationale":"Downstream rajya paani pe bhaari depend karte hain — isiliye toh woh use khone pe aapatti karte hain."}],"xp":10},"xp_reward":10},{"order_index":10,"turn_type":"tap_to_match","content":{"prompt":"Har term ko uske matlab se match karo.","left":[{"id":"l1","label":"Krishna-Godavari dispute"},{"id":"l2","label":"Har khet ko pani"},{"id":"l3","label":"Per drop more crop"},{"id":"l4","label":"Integrated water management"}],"right":[{"id":"r1","label":"Koyna pe diversion par jhagadte rajya"},{"id":"r2","label":"Har khet ko paani"},{"id":"r3","label":"Kam paani se zyaada fasal"},{"id":"r4","label":"Ek nadi ke poore basin ko ek saath plan karna"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":11,"turn_type":"exercise","content":{"instruction":"India mein inter-state water disputes aam hain. Ek naam batane ki koshish karo (Krishna-Godavari ek hai; Cauvery ek aur mashhoor hai).\n\nPaper pe likho kaunse rajya shaamil hain aur woh kis cheez pe jhagad rahe hain. Neeche dispute aur rajya type karo.\n","tool":"pencil","placeholder":"___ dispute, in rajyon ke beech..."},"xp_reward":15},{"order_index":12,"turn_type":"fill_in_the_blank","content":{"prompt":"Sharing problem aur fix ko lock karo.","template":"Jab ek nadi rajyon se guzarti hai, upstream zyaada paani lena {{blank-1}} flow ghataata hai; PMKSY ka slogan 'per drop more {{blank-2}}' paani-use efficiency pe zor deta hai.\n","answers":[{"id":"blank-1","accepted":["downstream","down-stream","Downstream"]},{"id":"blank-2","accepted":["crop","Crop"]}]},"xp_reward":10},{"order_index":13,"turn_type":"reflection","content":{"prompt":"Koi rajya us nadi ko *own* nahi karta jo kaiyon se behti hai — phir bhi har ek aise act karta hai jaise uska hissa uska apna ho. Rajyon ko ek shared nadi ko sach mein shared maanne ke liye kya lagega?\n\nKoi sahi jawaab nahi.\n","placeholder":"Rajyon ko ek nadi fairly share karne ke liye lagega..."},"xp_reward":5},{"order_index":14,"turn_type":"checkpoint","content":{"title":"Tum samjha sakte ho ki nadiyaan disputes kyun chhedti hain — aur unhe kaise baantna hai.","summary":"Ek nadi jo kayi rajyon se behti hai disputes chhedti hai, kyunki upstream use downstream flow ghataata hai — jaise Krishna-Godavari. Jawaab: integrated basin-wide management, aur khet pe, PMKSY ka \"har khet ko pani\" aur \"per drop more crop\".\n\nPar bade dams aur shared nadiyaan paani secure karne ka ekmatra tareeka nahi. Ek bahut puraana, bahut chhota idea hai — jo na ek nadi damming karta hai na ek padosi se ladta hai. Woh bas baarish ko wahin pakad leta hai jahan woh girti hai. Yahi aakhri course hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 3, 11, 100, 'ai_chat', true)
