  -- the-water-scarcity-puzzle/why-a-wet-country-runs-dry
  VALUES ((SELECT id FROM courses WHERE slug = 'the-water-scarcity-puzzle'), 'why-a-wet-country-runs-dry', $lj${"en":{"title":"Why a Wet Country Runs Dry","subtitle":"A city can sit right beside a river and still go thirsty"},"hinglish":{"title":"Ek Bheega Desh Sookh Kyun Jaata Hai","subtitle":"Ek sheher ek nadi ke bilkul paas baith ke bhi pyaasa reh sakta hai","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Yeh aisi cheez hai jo mumkin nahi honi chahiye: ek sheher ek nadi ke bilkul paas baitha, aur *phir bhi* paani ki kami mein.\n\nPhir bhi humare kayi sheher theek aise hi hain. Agar baarish problem nahi, toh kya hai?\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Water scarcity ki teen jad-wajahein hain — aur gaur karo ki inme se *koi* \"kam baarish\" nahi hai:\n\n- **over-exploitation**\n- **excessive use**\n- **unequal access**\n\nDekhte hain har ek ek aise desh ko kaise sukhaa deti hai jo asal mein kaafi bheega hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"**Wajah 1 — badhti population.**\n\nZyaada log zyaada paani maangte hain — sirf peene ko nahi, balki zyaada *khaana* ugaane ko. Food-grain badhaane ke liye, hum dry-season farming ke liye irrigation badhaane ko paani over-exploit karte hain.\n\nAur **irrigated agriculture India mein paani ka sabse bada akela consumer hai**. Kuein pe bheed badhti hi jaati hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"media","content":{"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch03-water-resources/c1l2-thirsty-city.png","caption":"Nadi ke bilkul paas basa sheher, phir bhi saamne ki zameen sookhi aur chatki hui — ek bheegi jagah jo phir bhi paani ki kami mein hai.","aspect_ratio":1.7778},"xp_reward":0},{"order_index":5,"turn_type":"svg_graphic","content":{"title":"PAANI KAUN USE KARTA HAI","caption":"Ek finite freshwater supply se — agriculture sabse bada hissa leti hai, kaafi aage se.","svg":"<svg viewBox=\"0 0 360 170\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"120\" y=\"8\" width=\"120\" height=\"26\" rx=\"5\" fill=\"#0ea5e9\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"180\" y=\"25\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#ffffff\">FRESHWATER</text>\n  <line x1=\"180\" y1=\"34\" x2=\"70\" y2=\"64\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n  <line x1=\"180\" y1=\"34\" x2=\"180\" y2=\"64\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n  <line x1=\"180\" y1=\"34\" x2=\"290\" y2=\"64\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n  <rect x=\"26\" y=\"64\" width=\"88\" height=\"92\" rx=\"5\" fill=\"#bbf7d0\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"70\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#166534\">Agriculture</text>\n  <text x=\"70\" y=\"100\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">largest</text>\n  <text x=\"70\" y=\"111\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">consumer</text>\n  <rect x=\"136\" y=\"96\" width=\"88\" height=\"60\" rx=\"5\" fill=\"#fde68a\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"180\" y=\"120\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#92400e\">Industry</text>\n  <rect x=\"246\" y=\"104\" width=\"88\" height=\"52\" rx=\"5\" fill=\"#e9d5ff\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"290\" y=\"128\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#6b21a8\">Homes</text>\n</svg>\n"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"**Wajah 2 — groundwater ka jaal.**\n\nKisaan zyaada zameen seenchne ko apne kuein aur tube-wells khodte hain. Samajhdaar lagta hai — jab tak tum samajh na lo ki sab yahi kar rahe hain.\n\nBahut zyaada pump karo, aur **groundwater levels girte hain**. Yeh paani ki availability *aur* aage chal ke food security ko nuksaan pahunchaata hai. Ek short-term jeet jo long-term haar ban jaati hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"**Wajah 3 — industries aur sheher.**\n\nIndependence ke baad, tezi se industrialisation aur urbanisation. Industries paani ki bhaari consumers hain — *aur* unhe power chahiye, jiska zyaadatar **hydroelectric** hai, toh bijli bhi chupchaap paani kharch karti hai.\n\nGhani aabaadi waale sheher aur urban lifestyles demand badhate hain. Housing societies apne borewells gaadte hain. Nateeja: naazuk water resources tab tak over-exploit jab tak woh khatam na ho jaayein.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"html_animation","content":{"title":"KUEIN PE BADI BHEED","caption":"Zyaada log, zyaada khet, zyaada factories — sab ek hi simatte supply se peete hue.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoDrop { 0%,15%{height:60px;fill:#0ea5e9} 85%,100%{height:18px;fill:#7dd3fc} }\n    @keyframes geoFade1 { 0%,10%{opacity:0} 30%,100%{opacity:1} }\n    @keyframes geoFade2 { 0%,35%{opacity:0} 55%,100%{opacity:1} }\n    @keyframes geoFade3 { 0%,60%{opacity:0} 80%,100%{opacity:1} }\n    .geo-w { animation: geoDrop 5s ease-in-out infinite alternate; }\n    .gf1{animation:geoFade1 5s infinite} .gf2{animation:geoFade2 5s infinite} .gf3{animation:geoFade3 5s infinite}\n  </style>\n  <svg viewBox=\"0 0 300 120\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <rect x=\"130\" y=\"40\" width=\"40\" height=\"60\" fill=\"#0ea5e9\" class=\"geo-w\"/>\n    <rect x=\"124\" y=\"34\" width=\"52\" height=\"8\" rx=\"3\" fill=\"#475569\"/>\n    <circle class=\"gf1\" cx=\"60\" cy=\"60\" r=\"12\" fill=\"#16a34a\"/>\n    <circle class=\"gf2\" cx=\"60\" cy=\"92\" r=\"12\" fill=\"#ca8a04\"/>\n    <circle class=\"gf3\" cx=\"240\" cy=\"76\" r=\"12\" fill=\"#7c3aed\"/>\n    <text x=\"150\" y=\"115\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0369a1\">the well drops as the crowd grows</text>\n  </svg>\n</div>\n"},"xp_reward":0},{"order_index":9,"turn_type":"tutor_message","content":{"text":"Teeno wajahon ko dobaara dekho. Inme se ek bhi *baarish* ke baare mein nahi.\n\nYeh **demand** ka renewable supply se aage nikalna hai — plus **unequal access**, jahan kuch ko bharpoor milta hai aur kuch ko lagbhag kuch nahi. Aise ek bheega desh sookh jaata hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":10,"turn_type":"mcq","content":{"question":"India mein paani ka sabse bada akela consumer kya hai?","options":[{"id":"a","text":"Ghar / domestic use.","is_correct":false,"rationale":"Ghar paani use karte hain, par unka hissa sabse bade consumer se kahin chhota hai."},{"id":"b","text":"Irrigated agriculture.","is_correct":true,"rationale":"Sahi — irrigated agriculture kaafi aage sabse bada consumer hai, isiliye irrigation badhaana paani over-exploit karta hai."},{"id":"c","text":"Hydroelectric power stations.","is_correct":false,"rationale":"Industry aur power bahut paani use karte hain, par kul milaa ke irrigated agriculture sabse bada consumer hai."},{"id":"d","text":"Maweshiyon ke liye peene ka paani.","is_correct":false,"rationale":"Ek asli use, par irrigated agriculture ke saamne bahut chhota."}],"xp":10},"xp_reward":10},{"order_index":11,"turn_type":"tap_to_match","content":{"prompt":"Scarcity ki har wajah ko us se match karo jisko woh le jaati hai.","left":[{"id":"l1","label":"Badhti population"},{"id":"l2","label":"Kisaan kuein over-pump karte"},{"id":"l3","label":"Zyaada industries"},{"id":"l4","label":"Ghane sheher apne borewells ke saath"}],"right":[{"id":"r1","label":"Zyaada khaana chahiye → zyaada irrigation"},{"id":"r2","label":"Girte groundwater levels"},{"id":"r3","label":"Bhaari paani use plus hydel power ki demand"},{"id":"r4","label":"Over-exploited, depleted local paani"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":12,"turn_type":"exercise","content":{"instruction":"Aaj tumhare ghar ne paani jin-jin tareekon se use kiya woh sab likho — peena, khaana banana, nahaana, dhona, garden, flush.\n\nPaper pe nishaan lagao kaunsa sabse zyaada use hua. Phir neeche apne ghar ka sabse bada akela paani use type karo.\n","tool":"pencil","placeholder":"Mere ghar ka sabse bada paani use hai..."},"xp_reward":15},{"order_index":13,"turn_type":"fill_in_the_blank","content":{"prompt":"Do bade drains ko lock karo.","template":"Irrigated {{blank-1}} paani ki sabse badi consumer hai, aur kuein over-pump karne se {{blank-2}} levels girte hain.\n","answers":[{"id":"blank-1","accepted":["agriculture","Agriculture","farming","kheti"]},{"id":"blank-2","accepted":["groundwater","ground water","Groundwater"]}]},"xp_reward":10},{"order_index":14,"turn_type":"reflection","content":{"prompt":"Har kisaan jo gehra kuaan khodta hai woh *apne liye* samajhdaari kar raha hai — par milke woh shared groundwater khaali kar dete hain. Zindagi mein aur kahan kai samajhdaar individual choices milke ek shared problem ban jaati hain?\n\nKoi sahi jawaab nahi.\n","placeholder":"Kai chhoti choices milke ek badi problem — jaise..."},"xp_reward":5},{"order_index":15,"turn_type":"checkpoint","content":{"title":"Tum bata sakte ho ki demand, na ki baarish, water scarcity chalati hai.","summary":"Irrigation ke liye over-exploitation (sabse bada user), bahut zyaada kuon se girta groundwater, aur industries aur sheheron ki pyaas — demand renewable supply se aage nikal jaati hai, aur access unequal rehti hai. Baarish mushkil se point hai.\n\nPar ek aur kism ki scarcity hai, aur woh chalaak hai: paani jo *wahin* hai par peene laayak nahi. Jab problem maatra nahi, quality ho toh kya hota hai? Yahi agli lesson hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 2, 12, 100, 'ai_chat', true)
