  -- the-water-scarcity-puzzle/when-water-isnt-safe-to-drink
  VALUES ((SELECT id FROM courses WHERE slug = 'the-water-scarcity-puzzle'), 'when-water-isnt-safe-to-drink', $lj${"en":{"title":"When Water Isn't Safe to Drink","subtitle":"A glass full to the brim — and not a drop fit to drink"},"hinglish":{"title":"Jab Paani Peene Laayak Na Ho","subtitle":"Ek glass labalab bhara — aur ek boond bhi peene laayak nahi","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Ek glass paani ki kalpana karo, bilkul kinaare tak bhara. Ab socho ki tum uski ek boond bhi nahi pee sakte.\n\nYeh water scarcity ki *teesri* kism hai — aur iska is se koi lena-dena nahi ki paani kitna hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Ab tak humne *quantity* scarcity gini — kaafi paani na hona.\n\nPar ek ilaaqa **bharpoor** paani rakh sakta hai aur *phir bhi* scarcity jhel sakta hai, ek alag wajah se: paani **bad quality** ka hai. Har glass bharne ko kaafi, par use karne ke liye unsafe.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"Use zehreela kya banata hai?\n\n**Domestic aur industrial wastes**, aur woh **chemicals, pesticides, aur fertilisers** jo humare kheton se beh ke aate hain. Yeh warna-bharpoor paani ko *hazardous* bana dete hain.\n\nBahut paani. Peene laayak ek boond nahi.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"media","content":{"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch03-water-resources/c1l3-polluted-water.png","caption":"Bharpoor paani — par dhundhla, polluted, peene laayak nahi. Scarcity *quality* ki bhi hoti hai, sirf maatra ki nahi.","aspect_ratio":1.7778},"xp_reward":0},{"order_index":5,"turn_type":"svg_graphic","content":{"title":"DO KISM KI SCARCITY","caption":"Quantity scarcity (paani nahi) — aur quality scarcity (bharpoor paani, par unsafe).","svg":"<svg viewBox=\"0 0 360 170\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"20\" y=\"14\" width=\"150\" height=\"142\" rx=\"8\" fill=\"#f8fafc\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"95\" y=\"34\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#0f172a\">Quantity</text>\n  <rect x=\"72\" y=\"70\" width=\"46\" height=\"64\" rx=\"4\" fill=\"#f1f5f9\" stroke=\"#475569\" stroke-width=\"2\"/>\n  <text x=\"95\" y=\"150\" text-anchor=\"middle\" font-size=\"8\" fill=\"#991b1b\">empty — too little water</text>\n  <rect x=\"190\" y=\"14\" width=\"150\" height=\"142\" rx=\"8\" fill=\"#f8fafc\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"265\" y=\"34\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#0f172a\">Quality</text>\n  <rect x=\"242\" y=\"70\" width=\"46\" height=\"64\" rx=\"4\" fill=\"#84cc16\" stroke=\"#475569\" stroke-width=\"2\" opacity=\"0.55\"/>\n  <circle cx=\"255\" cy=\"92\" r=\"3\" fill=\"#3f6212\"/><circle cx=\"276\" cy=\"104\" r=\"3\" fill=\"#3f6212\"/><circle cx=\"263\" cy=\"118\" r=\"3\" fill=\"#3f6212\"/>\n  <text x=\"265\" y=\"150\" text-anchor=\"middle\" font-size=\"8\" fill=\"#854d0e\">full — but polluted</text>\n</svg>\n"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"Toh India iske baare mein kya kar raha hai?\n\nPehla, **Jal Jeevan Mission (JJM)**. Iska goal: *har rural household* ko assured, potable **piped water** dena — 55 litre per person per day, bharosemand, long-term ke liye.\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"Doosra, **Atal Bhujal Yojana (Atal Jal)** — *groundwater* pe focus, 8,220 *water-stressed* Gram Panchayats mein chalti hui.\n\nIska key idea sirf pipe aur pump nahi. Yeh **behavioural change** hai — poori communities ko *consumption* ke attitude se *conservation* ke attitude tak shift karna.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"html_animation","content":{"title":"BHARA, PAR PEENE LAAYAK NAHI","caption":"Glass poora bharta hai — aur phir pollution ghus aata hai. Quantity sirf aadhi ladai hai.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoFillUp { 0%,10%{height:0} 45%,100%{height:70px} }\n    @keyframes geoPollute { 0%,50%{fill:#38bdf8} 90%,100%{fill:#84cc16} }\n    .geo-fill { animation: geoFillUp 5s ease-in-out infinite alternate, geoPollute 5s ease-in-out infinite alternate; }\n  </style>\n  <svg viewBox=\"0 0 200 120\" style=\"max-width:200px;width:100%\" font-family=\"sans-serif\">\n    <rect x=\"78\" y=\"22\" width=\"44\" height=\"76\" rx=\"4\" fill=\"none\" stroke=\"#475569\" stroke-width=\"2.5\"/>\n    <rect x=\"80\" y=\"28\" width=\"40\" height=\"70\" class=\"geo-fill\" />\n    <text x=\"100\" y=\"114\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0369a1\">full glass, unsafe water</text>\n  </svg>\n</div>\n"},"xp_reward":0},{"order_index":9,"turn_type":"tutor_message","content":{"text":"Yeh sab itna maayne kyun rakhta hai?\n\nPaani ko conserve aur manage karna humari **health**, **food security**, **livelihoods**, aur **ecosystems** ko bachata hai. Use over-exploit aur mismanage karo, aur tum ek *ecological crisis* chhed dete ho jo in sabko ek saath maarti hai.\n\nPaani sirf ek resource nahi. Yeh woh dhaaga hai jis pe yeh sab latke hain.\n","persona_id":"nova"},"xp_reward":0},{"order_index":10,"turn_type":"mcq","content":{"question":"Ek ilaaqe ko high annual rainfall milti hai, par uska paani bhaari pollute hai. Kya woh water scarcity jhel raha hai?","options":[{"id":"a","text":"Nahi — high rainfall ka matlab kaafi paani, toh koi scarcity nahi.","is_correct":false,"rationale":"Sirf quantity hi maayne nahi rakhti. Polluted paani use ke liye unsafe hai, toh ilaaqa scarce HAI."},{"id":"b","text":"Haan — paani jise tum safely use nahi kar sakte woh ek kism ki scarcity hai (quality scarcity).","is_correct":true,"rationale":"Sahi. Bharpoor par polluted paani phir bhi logon ko usable paani se vanchit chhodta hai — yeh *quality* ki scarcity hai."},{"id":"c","text":"Sirf tab agar rainfall baad mein ghat jaaye.","is_correct":false,"rationale":"Ilaaqa abhi *isi waqt* scarce hai — maujood paani unusable hai, chahe future rainfall kuch bhi ho."},{"id":"d","text":"Nahi — pollution ek alag problem hai, scarcity nahi.","is_correct":false,"rationale":"Pollution seedhe scarcity paida karta hai available paani ko unsafe bana ke."}],"xp":10},"xp_reward":10},{"order_index":11,"turn_type":"tap_to_match","content":{"prompt":"Har term ko uske matlab se match karo.","left":[{"id":"l1","label":"Jal Jeevan Mission"},{"id":"l2","label":"Atal Bhujal Yojana"},{"id":"l3","label":"Quality scarcity"},{"id":"l4","label":"Mukhya water pollutants"}],"right":[{"id":"r1","label":"Har rural ghar ko 55 litre piped potable paani"},{"id":"r2","label":"Groundwater — consumption se conservation tak shift"},{"id":"r3","label":"Kaafi paani, par use karne ke liye bahut polluted"},{"id":"r4","label":"Wastes, chemicals, pesticides, aur fertilisers"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":12,"turn_type":"exercise","content":{"instruction":"Ek chhota proposal (4–5 line) likho ki *tum* apni rozmarra zindagi mein paani kaise conserve kar sakte ho — nal pe, bathroom mein, kitchen mein, garden mein.\n\nWoh ek change chuno jo sabse zyaada bachaaye, aur neeche type karo.\n","tool":"pencil","placeholder":"Mera sabse bada paani-bachaane waala change hoga..."},"xp_reward":15},{"order_index":13,"turn_type":"fill_in_the_blank","content":{"prompt":"Quality scarcity aur mission ko lock karo.","template":"Scarcity bad water {{blank-1}} se aa sakti hai jab wastes aur chemicals use pollute karte hain; {{blank-2}} Jeevan Mission rural ghar ko piped potable paani pahunchaata hai.\n","answers":[{"id":"blank-1","accepted":["quality","Quality"]},{"id":"blank-2","accepted":["Jal","jal"]}]},"xp_reward":10},{"order_index":14,"turn_type":"reflection","content":{"prompt":"Atal Jal yeh shart lagaata hai ki asli fix *behaviour* hai — logon ko conservation ko value karna sikhana, sirf zyaada infrastructure banana nahi. Tumhe lagta hai aadtein badalna dams aur pipes banane se mushkil hai ya aasaan? Kyun?\n\nKoi sahi jawaab nahi.\n","placeholder":"Aadtein badalna versus cheezein banana — mujhe lagta hai..."},"xp_reward":5},{"order_index":15,"turn_type":"checkpoint","content":{"title":"Tum maatra AUR quality dono ki scarcity samajhte ho — aur India dono se kaise lad raha hai.","summary":"Paani sirf tab scarce nahi jab bahut kam ho, balki jab jo hai woh use karne ke liye bahut polluted ho. Jal Jeevan Mission rural ghar ko piped potable paani laata hai; Atal Jal groundwater ko sambhaalta hai communities ko consumption se conservation tak shift karke. Daanv pe: health, khaana, livelihoods, ecosystems.\n\nPar yeh sab ek practical sawaal khada karta hai jise hum ab tak taalte rahe: hum bade paimaane pe paani *store* aur manage *kaise* karte hain? Pichli sadi ke zyaadatar samay, India ka bada jawaab ek hi vishaal dhaancha tha — dam. Yahin se agla course shuru hota hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 3, 11, 100, 'ai_chat', true)
  ON CONFLICT (course_id, slug) DO UPDATE SET
    translations = excluded.translations,
    order_index = excluded.order_index,
    estimated_minutes = excluded.estimated_minutes,
    xp_reward = excluded.xp_reward,
    format = 'ai_chat',
    is_published = true
  RETURNING id INTO v_lesson;
  DELETE FROM lesson_turns WHERE lesson_id = v_lesson;

  DELETE FROM lessons l USING courses c
  WHERE l.course_id = c.id AND c.slug IN ('the-water-scarcity-puzzle','multi-purpose-river-projects','harvesting-the-rain')
    AND NOT EXISTS (SELECT 1 FROM lesson_turns t WHERE t.lesson_id = l.id);
  UPDATE courses c SET lesson_count = (SELECT count(*) FROM lessons l WHERE l.course_id = c.id)
  WHERE c.slug IN ('the-water-scarcity-puzzle','multi-purpose-river-projects','harvesting-the-rain');
END $deploy$;
