  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"What if, instead of building a giant dam to drag water across a whole state, you simply *caught the rain right where it fell*?\n\nIndia has been doing exactly that — brilliantly — for thousands of years.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"Ancient India had an *extraordinary* tradition of **water harvesting**.\n\nPeople knew their local **rainfall patterns** and **soil types** in deep detail, and built clever techniques to catch rainwater, groundwater, river water — even flood water — each one tuned to the local ecology.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"In the **hills and mountains**, people dug diversion channels — the **guls** and **kuls** of the Western Himalayas — to carry stream water down to their fields for farming.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'tutor_message', $lj${"text":"In the **flood plains of Bengal**, they built **inundation channels** to let the floods themselves irrigate their fields.\n\nAnd across many regions, **rooftop rainwater harvesting** caught and stored drinking water — especially in Rajasthan.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'svg_graphic', $lj${"title":"DIFFERENT LANDS, DIFFERENT METHODS","caption":"Every region invented a water-harvesting method to fit its own rainfall and soil.","svg":"<svg viewBox=\"0 0 360 176\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"10\" y=\"8\" width=\"166\" height=\"76\" rx=\"6\" fill=\"#eff6ff\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"93\" y=\"28\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#1e3a8a\">Western Himalayas</text>\n  <text x=\"93\" y=\"50\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">guls and kuls —</text>\n  <text x=\"93\" y=\"64\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">diversion channels</text>\n  <rect x=\"184\" y=\"8\" width=\"166\" height=\"76\" rx=\"6\" fill=\"#ecfeff\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"267\" y=\"28\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#0e7490\">Bengal flood plains</text>\n  <text x=\"267\" y=\"50\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">inundation channels —</text>\n  <text x=\"267\" y=\"64\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">floods irrigate fields</text>\n  <rect x=\"10\" y=\"92\" width=\"166\" height=\"76\" rx=\"6\" fill=\"#fffbeb\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"93\" y=\"112\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#92400e\">Jaisalmer (arid)</text>\n  <text x=\"93\" y=\"134\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">khadins — fields turned</text>\n  <text x=\"93\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">into rain-fed stores</text>\n  <rect x=\"184\" y=\"92\" width=\"166\" height=\"76\" rx=\"6\" fill=\"#fff7ed\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"267\" y=\"112\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#9a3412\">Rajasthan</text>\n  <text x=\"267\" y=\"134\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">johads + rooftop</text>\n  <text x=\"267\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">harvesting</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"In the **arid and semi-arid** regions, whole agricultural fields were turned into rain-fed storage — letting water *stand* and soak into the soil to moisten it.\n\nThe **khadins** of Jaisalmer and the **johads** in other parts of Rajasthan do exactly this: trap the rare rain, and make the land hold it.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'html_animation', $lj${"title":"CATCH IT WHERE IT FALLS","caption":"Instead of letting the rain run away, a small local structure catches and keeps it.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoRain { 0%{transform:translateY(-30px);opacity:0} 20%{opacity:1} 70%{transform:translateY(40px);opacity:1} 75%,100%{opacity:0} }\n    @keyframes geoStore { 0%,40%{height:2px} 75%,100%{height:26px} }\n    .geo-rd { animation: geoRain 3s linear infinite; }\n    .geo-rd2 { animation: geoRain 3s linear infinite; animation-delay:1s; }\n    .geo-store { animation: geoStore 3s ease-in infinite; }\n  </style>\n  <svg viewBox=\"0 0 240 120\" style=\"max-width:240px;width:100%\" font-family=\"sans-serif\">\n    <line class=\"geo-rd\" x1=\"100\" y1=\"20\" x2=\"100\" y2=\"34\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n    <line class=\"geo-rd2\" x1=\"140\" y1=\"20\" x2=\"140\" y2=\"34\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n    <path d=\"M70,92 Q120,70 170,92 L170,100 L70,100 Z\" fill=\"none\" stroke=\"#92400e\" stroke-width=\"2\"/>\n    <rect class=\"geo-store\" x=\"72\" y=\"72\" width=\"96\" height=\"26\" fill=\"#38bdf8\"/>\n    <text x=\"120\" y=\"114\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0369a1\">the rain is caught and held</text>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'tutor_message', $lj${"text":"Notice the whole philosophy here.\n\nNo giant dam. No fight with a neighbouring state. Just *local* knowledge, catching *local* rain, for *local* needs.\n\nSmall, smart, and very, very old.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'mcq', $lj${"question":"What are the 'guls' and 'kuls' of the Western Himalayas?","options":[{"id":"a","text":"Large multi-purpose dams for electricity.","is_correct":false,"rationale":"They're small traditional channels, not big dams — the opposite scale."},{"id":"b","text":"Diversion channels that carry stream water to fields for farming.","is_correct":true,"rationale":"Right — guls and kuls are hill diversion channels, a local water-harvesting method."},{"id":"c","text":"Underground tanks for storing drinking water.","is_correct":false,"rationale":"That describes Rajasthan's tankas, not the Himalayan guls and kuls."},{"id":"d","text":"Rooftop pipes for collecting rain.","is_correct":false,"rationale":"That's rooftop harvesting. Guls and kuls are diversion channels for stream water."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 10, 'tap_to_match', $lj${"prompt":"Match each harvesting method to its region.","left":[{"id":"l1","label":"Guls and kuls"},{"id":"l2","label":"Inundation channels"},{"id":"l3","label":"Khadins"},{"id":"l4","label":"Johads"}],"right":[{"id":"r1","label":"Western Himalayas"},{"id":"r2","label":"Flood plains of Bengal"},{"id":"r3","label":"Jaisalmer"},{"id":"r4","label":"Other parts of Rajasthan"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'exercise', $lj${"instruction":"Look around your own locality. Is there any way rainwater is caught and stored — a tank, a pond, a rooftop collection pipe, a check dam, a stepwell?\n\nOn paper, note what you find (or what *could* be built). Type one rainwater-harvesting structure near you below.\n","tool":"pencil","placeholder":"Near me, rainwater is (or could be) caught by..."}$lj$::jsonb, 15, true),
    (v_lesson, 12, 'fill_in_the_blank', $lj${"prompt":"Lock in two traditional methods.","template":"In the Western Himalayas, diversion channels called {{blank-1}} or kuls carry water to fields; in Jaisalmer, fields are turned into rain-fed stores called {{blank-2}}.\n","answers":[{"id":"blank-1","accepted":["guls","gul","Guls"]},{"id":"blank-2","accepted":["khadins","khadin","Khadins"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 13, 'reflection', $lj${"prompt":"For centuries, communities solved their own water problems with local knowledge — no engineers, no big budgets. Why do you think so much of that wisdom was forgotten? Should we bring it back?\n\nNo right answer.\n","placeholder":"That local wisdom faded because..."}$lj$::jsonb, 5, true),
    (v_lesson, 14, 'checkpoint', $lj${"title":"You can name India's traditional rain-catching methods by region.","summary":"Long before big dams, India caught its rain locally: guls and kuls in the Himalayas, inundation channels in Bengal, khadins in Jaisalmer, johads in Rajasthan — each tuned to its own land and rainfall.\n\nOne of these methods became so refined it could hold a year's drinking water in a single underground room. In the deserts of the Thar, the rooftop and the *tanka* turned rare rain into a lifeline. That's the next lesson.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"In the Thar desert, the most precious thing in a house often wasn't gold or land.\n\nIt was a room-sized hole in the ground — kept full of rain. They called it a **tanka**.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"Across Rajasthan — in Bikaner, Phalodi, Barmer — almost *every* house traditionally had an underground tank, a **tanka**, for storing drinking water.\n\nSome were enormous. One in Phalodi was **6.1 metres deep, 4.27 metres long, and 2.44 metres wide** — a small room, filled with water.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"The tanka was part of a clever **rooftop rainwater harvesting** system.\n\nBuilt inside the main house or the courtyard, it was connected to the **sloping roof** by a pipe. Rain hits the roof, runs down the pipe, and fills the tanka underground. Simple, and brilliant.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'svg_graphic', $lj${"title":"ROOFTOP TO TANKA","caption":"Rain on the sloping roof runs down a pipe into a room-sized underground tank.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <line x1=\"40\" y1=\"20\" x2=\"60\" y2=\"20\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n  <line x1=\"90\" y1=\"16\" x2=\"110\" y2=\"16\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n  <polygon points=\"40,60 180,30 180,60\" fill=\"#fca5a5\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"110\" y=\"52\" text-anchor=\"middle\" font-size=\"8\" fill=\"#7f1d1d\">sloping roof</text>\n  <rect x=\"40\" y=\"60\" width=\"140\" height=\"48\" fill=\"#fef3c7\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"110\" y=\"88\" text-anchor=\"middle\" font-size=\"8\" fill=\"#92400e\">house</text>\n  <line x1=\"178\" y1=\"34\" x2=\"178\" y2=\"120\" stroke=\"#475569\" stroke-width=\"4\"/>\n  <text x=\"196\" y=\"80\" font-size=\"8\" fill=\"#475569\">pipe</text>\n  <rect x=\"150\" y=\"120\" width=\"120\" height=\"48\" rx=\"4\" fill=\"#7dd3fc\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"210\" y=\"142\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#075985\">TANKA</text>\n  <text x=\"210\" y=\"156\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0c4a6e\">underground store</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'tutor_message', $lj${"text":"One detail shows how careful they were.\n\nThe **first spell of rain** was *not* collected. It was allowed to wash all the dust off the roofs and pipes first. Only the *later* showers — now clean — were stored in the tanka.\n\nA built-in filter, made of patience.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"Why go to all this trouble? Because the tanka held that water until the **next rainfall** — a reliable source of drinking water through the brutal summers, when every other source dried up.\n\nThey even had a name for this rainwater: **palar pani** — *the purest form of natural water*.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"There was a bonus, too.\n\nMany houses built an underground room *right beside* the tanka. The cool stored water kept that room cool — a natural air-conditioner against the desert heat. One structure, two gifts.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'html_animation', $lj${"title":"THE TANKA FILLS","caption":"Rain on the roof, down the pipe, into the tanka — a year's drinking water, stored.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoTankaRain { 0%{transform:translateY(-20px);opacity:0} 25%{opacity:1} 70%{transform:translateY(70px);opacity:1} 80%,100%{opacity:0} }\n    @keyframes geoTankaFill { 0%,30%{height:3px} 80%,100%{height:34px} }\n    .geo-tr{animation:geoTankaRain 3s linear infinite} .geo-tr2{animation:geoTankaRain 3s linear infinite;animation-delay:1.2s}\n    .geo-tf{animation:geoTankaFill 3s ease-in infinite}\n  </style>\n  <svg viewBox=\"0 0 240 130\" style=\"max-width:240px;width:100%\" font-family=\"sans-serif\">\n    <polygon points=\"30,40 130,20 130,40\" fill=\"#fca5a5\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n    <line class=\"geo-tr\" x1=\"70\" y1=\"6\" x2=\"70\" y2=\"18\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n    <line class=\"geo-tr2\" x1=\"100\" y1=\"6\" x2=\"100\" y2=\"18\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n    <line x1=\"128\" y1=\"24\" x2=\"128\" y2=\"80\" stroke=\"#475569\" stroke-width=\"4\"/>\n    <rect x=\"100\" y=\"80\" width=\"90\" height=\"40\" rx=\"4\" fill=\"none\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n    <rect class=\"geo-tf\" x=\"103\" y=\"86\" width=\"84\" height=\"34\" fill=\"#38bdf8\"/>\n    <text x=\"145\" y=\"128\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0369a1\">tanka filling underground</text>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'tutor_message', $lj${"text":"Sadly, in western Rajasthan this tradition is fading.\n\nThe perennial **Indira Gandhi Canal** now brings plenty of water, so fewer people bother to maintain their tankas. Though some still do — because they prefer the taste of *palar pani* to the taste of tap water.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'mcq', $lj${"question":"Why was the first spell of rain deliberately NOT collected in the tanka?","options":[{"id":"a","text":"Because the first rain is poisonous.","is_correct":false,"rationale":"It isn't poisonous — it's just dirty. It was used to rinse, not because it's toxic."},{"id":"b","text":"To let it wash the dust off the roofs and pipes first, so only clean water is stored.","is_correct":true,"rationale":"Exactly — the first rain cleans the roof and pipe; the later, cleaner showers are then stored."},{"id":"c","text":"Because the tanka is always already full.","is_correct":false,"rationale":"The tanka empties over the dry months — the whole point of harvesting is to refill it."},{"id":"d","text":"Because the first rain evaporates instantly.","is_correct":false,"rationale":"It doesn't evaporate instantly — it's diverted on purpose to clean the system."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'tap_to_match', $lj${"prompt":"Match each term to what it means.","left":[{"id":"l1","label":"Tanka"},{"id":"l2","label":"Palar pani"},{"id":"l3","label":"The first spell of rain"},{"id":"l4","label":"Indira Gandhi Canal"}],"right":[{"id":"r1","label":"An underground tank for storing drinking water"},{"id":"r2","label":"Rainwater — the purest natural water"},{"id":"r3","label":"Washes the roof; not stored"},{"id":"r4","label":"Why rooftop harvesting is now declining"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'exercise', $lj${"instruction":"Sketch a simple rooftop-to-tank system for *your* home: where the rain lands, where the pipe goes, where the tank sits.\n\nOn paper, note one problem you'd have to solve (dust? overflow? space?). Type your biggest design challenge below.\n","tool":"pencil","placeholder":"To harvest rain at my home, the hardest part would be..."}$lj$::jsonb, 15, true),
    (v_lesson, 13, 'fill_in_the_blank', $lj${"prompt":"Lock in the desert system.","template":"Rooftop rain runs down a pipe into an underground tank called a {{blank-1}}; this rainwater, the purest natural water, is called {{blank-2}} pani.\n","answers":[{"id":"blank-1","accepted":["tanka","Tanka","tank"]},{"id":"blank-2","accepted":["palar","Palar"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 14, 'reflection', $lj${"prompt":"When the canal arrived, people stopped maintaining a system that had served them for centuries. Is it always progress to replace the old, self-reliant way with a piped supply from far away? What's gained — and what's lost?\n\nNo right answer.\n","placeholder":"Trading the tanka for the canal, we gained ___ but lost..."}$lj$::jsonb, 5, true),
    (v_lesson, 15, 'checkpoint', $lj${"title":"You can explain how the Thar's rooftop-and-tanka system worked.","summary":"Across Rajasthan, sloping roofs fed rain down pipes into room-sized underground tankas — storing palar pani, the purest water, through the dry summers, even cooling an adjoining room. The first rain was sacrificed to clean the system. Only the canal has made people forget it.\n\nBut this old idea isn't dead. Across India today, villages and even whole states are reviving rainwater harvesting — and proving it still works, beautifully. That's the final lesson, and the close of this chapter.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"A village so good at catching rain that it's officially called *\"rich in rainwater.\"* A state that made harvesting the rain the **law**. Bamboo pipes still watering crops after 200 years.\n\nThe old wisdom isn't a museum piece. It's back — and working.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"Across India today, traditional rainwater harvesting is being revived in homes, villages, and whole states — proving it can still meet real needs.\n\nLet's meet four places where it's thriving.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"First, **Gendathur**, a remote village in Mysuru, Karnataka.\n\nNearly **200 households** installed rooftop rainwater harvesting. It worked so well that the village earned a rare title: it became known as *rich in rainwater*.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'tutor_message', $lj${"text":"The numbers explain why.\n\nGendathur gets about **1,000 mm** of rain a year. With good rooftops and around ten fillings a year, each house can collect roughly **50,000 litres** — just from the rain landing on its own roof.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'svg_graphic', $lj${"title":"GENDATHUR'S RAINWATER MATH","caption":"1,000 mm of rain a year, caught from one rooftop, becomes about 50,000 litres per house.","svg":"<svg viewBox=\"0 0 360 160\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <line x1=\"40\" y1=\"16\" x2=\"56\" y2=\"16\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n  <line x1=\"80\" y1=\"12\" x2=\"96\" y2=\"12\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n  <line x1=\"120\" y1=\"16\" x2=\"136\" y2=\"16\" stroke=\"#2563eb\" stroke-width=\"3\"/>\n  <text x=\"88\" y=\"40\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#0369a1\">1,000 mm rain / year</text>\n  <polygon points=\"40,76 150,52 150,76\" fill=\"#fca5a5\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <rect x=\"40\" y=\"76\" width=\"110\" height=\"36\" fill=\"#fef3c7\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"95\" y=\"98\" text-anchor=\"middle\" font-size=\"8\" fill=\"#92400e\">one rooftop</text>\n  <text x=\"200\" y=\"90\" font-size=\"18\" fill=\"#475569\">→</text>\n  <rect x=\"230\" y=\"58\" width=\"110\" height=\"70\" rx=\"6\" fill=\"#7dd3fc\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"285\" y=\"92\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"bold\" fill=\"#075985\">~50,000 L</text>\n  <text x=\"285\" y=\"108\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0c4a6e\">per house, per year</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"Now an irony you won't forget. In **Shillong, Meghalaya**, rooftop harvesting is the most common practice — even though nearby **Cherrapunji** and **Mawsynram** get the **highest rainfall in the world**.\n\nYet Shillong itself faces an acute water shortage. So nearly every household harvests rain, drawing **15–25%** of its water from the rooftop. The wettest corner of Earth, still catching every drop.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"Some places made it official. **Tamil Nadu** became the **first Indian state to make rooftop rainwater harvesting compulsory** for *every* house — with legal punishment for those who don't comply.\n\nHarvesting the rain, written into law.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'html_animation', $lj${"title":"THE REVIVAL","caption":"From a Karnataka village to a Meghalaya capital to a state law — old wisdom, spreading again.","html":"<div style=\"background:#f0f9ff;padding:18px 14px;border-radius:12px;\">\n  <style>\n    @keyframes geoRev1 { 0%,5%{opacity:0;transform:translateY(8px)} 24%,100%{opacity:1;transform:none} }\n    @keyframes geoRev2 { 0%,30%{opacity:0;transform:translateY(8px)} 49%,100%{opacity:1;transform:none} }\n    @keyframes geoRev3 { 0%,55%{opacity:0;transform:translateY(8px)} 74%,100%{opacity:1;transform:none} }\n    .geo-rv{display:block;margin:5px 0;font:bold 11px sans-serif;color:#075985;background:#bae6fd;border-radius:6px;padding:6px 10px}\n    .grv1{animation:geoRev1 5s infinite} .grv2{animation:geoRev2 5s infinite} .grv3{animation:geoRev3 5s infinite}\n  </style>\n  <div class=\"geo-rv grv1\">Gendathur, Karnataka — \"rich in rainwater\"</div>\n  <div class=\"geo-rv grv2\">Shillong, Meghalaya — harvest despite the rain</div>\n  <div class=\"geo-rv grv3\">Tamil Nadu — harvesting made compulsory</div>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'tutor_message', $lj${"text":"And one beautiful old technique still runs in **Meghalaya**: **bamboo drip irrigation**, a **200-year-old** system.\n\nBamboo pipes tap stream and spring water. About **18–20 litres** enters the system, travels *hundreds of metres*, and arrives as just **20–80 drops per minute** — delivered right to the roots of each plant. Ancient engineering, with the efficiency of modern drip irrigation.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'mcq', $lj${"question":"Which was the first Indian state to make rooftop rainwater harvesting compulsory for all houses?","options":[{"id":"a","text":"Rajasthan","is_correct":false,"rationale":"Rajasthan has the deepest tradition of tankas, but it wasn't the first to make harvesting compulsory by law."},{"id":"b","text":"Tamil Nadu","is_correct":true,"rationale":"Correct — Tamil Nadu was the first state to make rooftop rainwater harvesting compulsory, with penalties for defaulters."},{"id":"c","text":"Meghalaya","is_correct":false,"rationale":"Meghalaya has Shillong's rooftop harvesting and bamboo drip irrigation, but didn't make harvesting compulsory statewide first."},{"id":"d","text":"Karnataka","is_correct":false,"rationale":"Karnataka has Gendathur, the 'rich in rainwater' village — but Tamil Nadu was first to legislate harvesting."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'tap_to_match', $lj${"prompt":"Match each place or system to its claim to fame.","left":[{"id":"l1","label":"Gendathur (Karnataka)"},{"id":"l2","label":"Shillong (Meghalaya)"},{"id":"l3","label":"Tamil Nadu"},{"id":"l4","label":"Bamboo drip irrigation"}],"right":[{"id":"r1","label":"Village known as 'rich in rainwater'"},{"id":"r2","label":"Harvests rain despite the world's highest rainfall nearby"},{"id":"r3","label":"First state to make harvesting compulsory"},{"id":"r4","label":"200-year-old bamboo-pipe system in Meghalaya"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'exercise', $lj${"instruction":"Find one more rainwater-harvesting system that exists in or around your locality — or design a simple one for your school or home.\n\nOn paper, describe how the water gets caught, stored, and used. Type your one-line idea below.\n","tool":"pencil","placeholder":"A harvesting system for my school/home would..."}$lj$::jsonb, 15, true),
    (v_lesson, 13, 'fill_in_the_blank', $lj${"prompt":"Lock in the modern revival.","template":"{{blank-1}} was the first Indian state to make rooftop rainwater harvesting compulsory; in Meghalaya, {{blank-2}} pipes carry spring water in a 200-year-old drip system.\n","answers":[{"id":"blank-1","accepted":["Tamil Nadu","tamil nadu","TamilNadu"]},{"id":"blank-2","accepted":["bamboo","Bamboo"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 14, 'reflection', $lj${"prompt":"Across this whole chapter — scarcity, dams, and harvesting — what's the one idea about water you'll actually carry with you? Name it, and why it stuck.\n\nNo right answer. This is your takeaway.\n","placeholder":"The idea I'm keeping is..."}$lj$::jsonb, 5, true),
    (v_lesson, 15, 'checkpoint', $lj${"title":"The whole chapter is yours: scarcity, dams, and harvesting the rain.","summary":"From Gendathur's rain-rich rooftops to Shillong's necessity, from Tamil Nadu's law to Meghalaya's 200-year-old bamboo pipes — India is proving that old water wisdom still works. And that closes the chapter.\n\nYou learned that water is renewable yet scarce — drained by demand, not just drought, and sometimes ruined by pollution; you can weigh the promise of multi-purpose dams against their heavy costs and the disputes they spark; and you've seen the oldest, smallest, smartest answer of all — catching the rain where it falls.\n\nNext time it rains, you'll see it differently: not as weather, but as a resource running past, asking to be caught.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Build one wall across a river, and you can light a city, water a desert, hold back a flood, and breed fish — all at the same time.\n\nIt sounds like magic. It's a **dam**. Let's see how it pulls off so many jobs at once.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"India has been doing this for *millennia*.\n\nSringaverapura had a flood-water harvesting system in the **1st century BC**. Chandragupta Maurya's era built dams and lakes. The 11th-century **Bhopal Lake** and Delhi's **Hauz Khas** tank followed. Modern India just kept an ancient tradition going — with concrete.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"So what *is* a dam, exactly?\n\nA **barrier across flowing water** that obstructs, directs, or slows the flow — usually creating a **reservoir**, a lake of stored water behind it. Most dams have a **spillway** that lets excess water flow over safely, so the dam doesn't burst.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch03-water-resources/c2l1-dam.png","caption":"A multi-purpose dam: one concrete wall holding back a vast reservoir, water thundering through the spillway.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'svg_graphic', $lj${"title":"ANATOMY OF A DAM","caption":"A barrier holds back a reservoir; a spillway releases the excess; the river continues below.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"0\" y=\"60\" width=\"180\" height=\"100\" fill=\"#7dd3fc\"/>\n  <text x=\"80\" y=\"100\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#075985\">RESERVOIR</text>\n  <text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0c4a6e\">stored water</text>\n  <polygon points=\"180,60 220,60 210,160 180,160\" fill=\"#94a3b8\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"200\" y=\"120\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#1e293b\" transform=\"rotate(90 200 120)\">DAM</text>\n  <path d=\"M180,62 Q200,58 220,68 L222,82 Q200,72 184,80 Z\" fill=\"#38bdf8\"/>\n  <text x=\"240\" y=\"58\" font-size=\"8\" fill=\"#0369a1\">spillway</text>\n  <line x1=\"225\" y1=\"70\" x2=\"232\" y2=\"58\" stroke=\"#0369a1\" stroke-width=\"1\"/>\n  <rect x=\"210\" y=\"140\" width=\"150\" height=\"20\" fill=\"#7dd3fc\"/>\n  <text x=\"290\" y=\"154\" text-anchor=\"middle\" font-size=\"8\" fill=\"#075985\">river continues</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"Dams used to be built for just *one* job: irrigation — storing rainwater to water fields later.\n\nToday they're **multi-purpose** — one dam, many jobs at once:\n\n- irrigation\n- electricity (**hydel power**)\n- water supply for homes and industry\n- flood control\n- recreation, inland navigation, and fish breeding\n\nThe Swiss Army knife of rivers.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"Two famous examples show the idea.\n\n**Bhakra-Nangal**, on the Sutlej-Beas, is used for *both* hydel power *and* irrigation. **Hirakud**, on the Mahanadi, integrates water *conservation* with *flood control*.\n\nIn each, the many uses of the stored water are woven together — that's what \"integrated\" means.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'html_animation', $lj${"title":"ONE DAM, MANY JOBS","caption":"Power, crops, drinking water, fish, flood control — all from a single project.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoJob1 { 0%,5%{opacity:.15} 20%,100%{opacity:1} }\n    @keyframes geoJob2 { 0%,25%{opacity:.15} 40%,100%{opacity:1} }\n    @keyframes geoJob3 { 0%,45%{opacity:.15} 60%,100%{opacity:1} }\n    @keyframes geoJob4 { 0%,65%{opacity:.15} 80%,100%{opacity:1} }\n    .geo-j { display:inline-block; margin:4px; padding:6px 12px; border-radius:999px; font:bold 11px sans-serif; color:#fff; }\n    .gj1{background:#ca8a04;animation:geoJob1 5s infinite} .gj2{background:#16a34a;animation:geoJob2 5s infinite}\n    .gj3{background:#0891b2;animation:geoJob3 5s infinite} .gj4{background:#7c3aed;animation:geoJob4 5s infinite}\n  </style>\n  <div style=\"font:bold 20px sans-serif;color:#075985;margin-bottom:8px\">one dam</div>\n  <span class=\"geo-j gj1\">electricity</span><span class=\"geo-j gj2\">irrigation</span><span class=\"geo-j gj3\">water supply</span><span class=\"geo-j gj4\">flood control</span>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'tutor_message', $lj${"text":"Jawaharlal Nehru proudly called dams the **\"temples of modern India.\"**\n\nWhy *temples*? Because he saw them weaving together farming and the village economy with rapid industrialisation and urban growth — the engine to lift a newly independent nation out of its colonial past.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'mcq', $lj${"question":"What makes a dam a 'multi-purpose' project?","options":[{"id":"a","text":"It is taller than an ordinary dam.","is_correct":false,"rationale":"Height classifies dams, but 'multi-purpose' is about *uses*, not size."},{"id":"b","text":"Its stored water serves many integrated uses at once — irrigation, power, supply, flood control, and more.","is_correct":true,"rationale":"Exactly. A multi-purpose dam weaves together many uses of the same impounded water."},{"id":"c","text":"It is built by many different states together.","is_correct":false,"rationale":"Who builds it isn't the point — 'multi-purpose' refers to the many things the dam *does*."},{"id":"d","text":"It is used only for generating electricity.","is_correct":false,"rationale":"That would be single-purpose. Multi-purpose means several uses combined."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'tap_to_match', $lj${"prompt":"Match each term to what it is.","left":[{"id":"l1","label":"Bhakra-Nangal"},{"id":"l2","label":"Hirakud"},{"id":"l3","label":"Spillway"},{"id":"l4","label":"Reservoir"}],"right":[{"id":"r1","label":"Hydel power plus irrigation (Sutlej-Beas)"},{"id":"r2","label":"Water conservation plus flood control (Mahanadi)"},{"id":"r3","label":"Lets excess water flow over safely"},{"id":"r4","label":"The lake of stored water behind the dam"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'exercise', $lj${"instruction":"Think about your own region. If a multi-purpose dam served it, which of its uses would matter most — electricity, irrigation, drinking water, or flood control?\n\nOn paper, rank your top two and say why. Type your number-one use below.\n","tool":"pencil","placeholder":"For my region, the most important use would be..."}$lj$::jsonb, 15, true),
    (v_lesson, 13, 'fill_in_the_blank', $lj${"prompt":"Lock in the basics.","template":"A dam holds back a lake of stored water called a {{blank-1}}, and Nehru called dams the temples of modern {{blank-2}}.\n","answers":[{"id":"blank-1","accepted":["reservoir","Reservoir"]},{"id":"blank-2","accepted":["India","india"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 14, 'reflection', $lj${"prompt":"Nehru called dams *temples* — almost sacred symbols of progress. Why do you think a new nation needed symbols like that, not just useful structures?\n\nNo right answer.\n","placeholder":"A young nation needed symbols because..."}$lj$::jsonb, 5, true),
    (v_lesson, 15, 'checkpoint', $lj${"title":"You can explain what a multi-purpose dam is and why it was celebrated.","summary":"A dam is a barrier that stores water in a reservoir; a multi-purpose project weaves together irrigation, power, water supply, flood control, and more — like Bhakra-Nangal and Hirakud. Nehru hailed them as the temples of modern India.\n\nBut every temple has a price. Over time, these giant projects came under fierce criticism — for what they do to rivers, land, and people. What's the hidden cost of a big dam? That's the next lesson.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Here's the cruel irony at the heart of this lesson: dams built to *stop* floods have sometimes *triggered* them.\n\nThe temple turned on its worshippers. Let's see how a structure so useful can do so much harm.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"It starts with one fact: by damming a river, you change its **natural flow**. And that one change sets off a whole chain of damage.\n\nBegin with what the river carries — sediment.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"A free-flowing river carries **sediment** (silt) downstream. Dam it, and that silt settles at the bottom of the reservoir — **excessive sedimentation** — while the river *below* the dam runs sediment-starved.\n\nThe result downstream: **rockier streambeds** and poorer habitats for the river's aquatic life.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'tutor_message', $lj${"text":"Dams also **fragment** rivers — they're walls. Fish and other aquatic fauna can no longer migrate past them, which is deadly when they need to travel upstream to **spawn**.\n\nAnd the reservoir floods the floodplain, **submerging** vegetation and soil that then slowly rot underwater.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch03-water-resources/c2l2-displaced-village.png","caption":"When the reservoir rises, whole villages go under — rooftops above the water, families moving to higher ground. The human cost of a big dam.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'svg_graphic', $lj${"title":"FREE RIVER vs DAMMED RIVER","caption":"A free river spreads silt and lets fish migrate; a dam traps the silt and blocks the fish.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <text x=\"10\" y=\"22\" font-size=\"9\" font-weight=\"bold\" fill=\"#166534\">Free river</text>\n  <rect x=\"10\" y=\"28\" width=\"340\" height=\"22\" fill=\"#7dd3fc\"/>\n  <circle cx=\"60\" cy=\"39\" r=\"3\" fill=\"#a16207\"/><circle cx=\"120\" cy=\"39\" r=\"3\" fill=\"#a16207\"/><circle cx=\"200\" cy=\"39\" r=\"3\" fill=\"#a16207\"/><circle cx=\"290\" cy=\"39\" r=\"3\" fill=\"#a16207\"/>\n  <text x=\"300\" y=\"64\" text-anchor=\"middle\" font-size=\"7\" fill=\"#166534\">silt + fish move freely →</text>\n  <text x=\"10\" y=\"100\" font-size=\"9\" font-weight=\"bold\" fill=\"#991b1b\">Dammed river</text>\n  <rect x=\"10\" y=\"106\" width=\"150\" height=\"22\" fill=\"#38bdf8\"/>\n  <circle cx=\"40\" cy=\"117\" r=\"3\" fill=\"#a16207\"/><circle cx=\"80\" cy=\"117\" r=\"3\" fill=\"#a16207\"/><circle cx=\"130\" cy=\"117\" r=\"3\" fill=\"#a16207\"/>\n  <polygon points=\"160,98 178,98 172,150 160,150\" fill=\"#94a3b8\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <rect x=\"178\" y=\"116\" width=\"172\" height=\"12\" fill=\"#7dd3fc\"/>\n  <text x=\"85\" y=\"144\" text-anchor=\"middle\" font-size=\"7\" fill=\"#991b1b\">silt trapped, fish blocked</text>\n  <text x=\"264\" y=\"144\" text-anchor=\"middle\" font-size=\"7\" fill=\"#991b1b\">rocky, starved streambed</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"It gets worse.\n\nReservoirs can **induce earthquakes**, breed **water-borne diseases** and pests, and cause pollution from over-use. And cruelly, dams built to *control* floods have sometimes *caused* them — sedimentation fills the reservoir, and in heavy rain the big dams often fail to hold a flood back at all.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'tutor_message', $lj${"text":"There's a farming sting too.\n\nThe floodplains below lose their yearly coat of **silt** — a free natural fertiliser — which adds to land degradation. And irrigation pushes farmers toward **water-intensive, commercial crops**, which over time **salinise** the soil (salt builds up and poisons it).\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'tutor_message', $lj${"text":"And the heaviest cost is human.\n\nBig dams submerge whole villages and fields, causing **large-scale displacement and loss of livelihood**. The **Sardar Sarovar** dam on the Narmada became the symbol of this struggle.\n\n(The flood-prone **Damodar** was long called the *\"river of sorrow.\"*)\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'html_animation', $lj${"title":"THE HIDDEN COSTS","caption":"Trapped silt, blocked fish, salted soil, displaced homes — the bill a big dam runs up.","html":"<div style=\"background:#fff7ed;padding:18px 14px;border-radius:12px;\">\n  <style>\n    @keyframes geoCost1 { 0%,5%{opacity:0;transform:translateX(-10px)} 24%,100%{opacity:1;transform:none} }\n    @keyframes geoCost2 { 0%,28%{opacity:0;transform:translateX(-10px)} 47%,100%{opacity:1;transform:none} }\n    @keyframes geoCost3 { 0%,51%{opacity:0;transform:translateX(-10px)} 70%,100%{opacity:1;transform:none} }\n    @keyframes geoCost4 { 0%,74%{opacity:0;transform:translateX(-10px)} 92%,100%{opacity:1;transform:none} }\n    .geo-c{display:block;margin:5px 0;font:bold 11px sans-serif;color:#7c2d12;background:#fed7aa;border-radius:6px;padding:6px 10px}\n    .gc1{animation:geoCost1 5s infinite} .gc2{animation:geoCost2 5s infinite} .gc3{animation:geoCost3 5s infinite} .gc4{animation:geoCost4 5s infinite}\n  </style>\n  <div class=\"geo-c gc1\">Silt trapped → poorer soil & aquatic life</div>\n  <div class=\"geo-c gc2\">Rivers fragmented → fish can't migrate</div>\n  <div class=\"geo-c gc3\">Soil salinised by water-intensive crops</div>\n  <div class=\"geo-c gc4\">Villages submerged → people displaced</div>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 11, 'mcq', $lj${"question":"Which of these is NOT an argument *in favour* of multi-purpose river projects?","options":[{"id":"a","text":"They bring water to areas that suffer from water scarcity.","is_correct":false,"rationale":"That IS a point in their favour — supplying scarce regions is a key benefit."},{"id":"b","text":"By regulating water flow, they help control floods.","is_correct":false,"rationale":"That's a benefit (in theory) — flood control is one of their stated purposes."},{"id":"c","text":"They lead to large-scale displacement and loss of livelihood.","is_correct":true,"rationale":"Correct — this is a *cost*, an argument *against* big dams, not in favour of them."},{"id":"d","text":"They generate electricity for our industries and homes.","is_correct":false,"rationale":"That's a benefit — hydel power is one of the main reasons dams are built."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'tap_to_match', $lj${"prompt":"Match each harm to what causes it.","left":[{"id":"l1","label":"Excessive sedimentation"},{"id":"l2","label":"Fish can't migrate to spawn"},{"id":"l3","label":"Soil salinisation"},{"id":"l4","label":"Displacement of people"}],"right":[{"id":"r1","label":"Silt settles in the reservoir instead of flowing on"},{"id":"r2","label":"The dam fragments the river with a wall"},{"id":"r3","label":"A shift to water-intensive commercial crops"},{"id":"r4","label":"The reservoir submerges villages and fields"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 13, 'exercise', $lj${"instruction":"Think of a dam or reservoir you've heard of (Sardar Sarovar, Bhakra-Nangal, or a local one).\n\nOn paper, list one clear *benefit* and one clear *cost* it brings. Type the dam's name and its biggest cost below.\n","tool":"pencil","placeholder":"The ___ dam — its biggest cost is..."}$lj$::jsonb, 15, true),
    (v_lesson, 14, 'fill_in_the_blank', $lj${"prompt":"Lock in two big costs.","template":"Damming a river traps {{blank-1}} in the reservoir instead of letting it flow on, and submerging villages forces people into {{blank-2}}.\n","answers":[{"id":"blank-1","accepted":["silt","sediment","Silt"]},{"id":"blank-2","accepted":["displacement","Displacement"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 15, 'reflection', $lj${"prompt":"A dam can power a million homes — and drown the homes of a few thousand villagers. How should a country weigh a benefit for many against a heavy cost for a few? Be honest about how hard this is.\n\nNo right answer.\n","placeholder":"Weighing the many against the few, I think..."}$lj$::jsonb, 5, true),
    (v_lesson, 16, 'checkpoint', $lj${"title":"You can weigh the real costs of big dams against their benefits.","summary":"Damming a river traps silt, starves and fragments habitats, salinises soil, can induce quakes and even worsen floods — and, hardest of all, displaces whole communities, as the Narmada struggle showed.\n\nAnd there's one more conflict big projects create: when a single river runs through several states, *who gets the water?* How do we share a river fairly? That's the next lesson.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"A river doesn't care about state borders. It just flows.\n\nSo when one river runs through five states, here's the awkward question nobody can avoid: *who owns the water?*\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"A single river often passes through *many* states, and each one wants its share. The catch: when an upstream state takes more, every state downstream gets **less**.\n\nThat tension has a name — **inter-state water disputes**.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"Take the **Krishna-Godavari dispute**.\n\nMaharashtra wanted to divert more water at **Koyna** for a multi-purpose project. But that would cut the **downstream flow** into Karnataka and Andhra Pradesh — harming *their* agriculture and industry. So those two states objected.\n\nOne river, three governments, one fight.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'svg_graphic', $lj${"title":"ONE RIVER, THREE STATES","caption":"Take more water upstream, and less reaches the states downstream — the root of the dispute.","svg":"<svg viewBox=\"0 0 360 170\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <polygon points=\"20,60 130,60 130,84 20,96\" fill=\"#38bdf8\"/>\n  <polygon points=\"130,62 240,66 240,82 130,82\" fill=\"#7dd3fc\"/>\n  <polygon points=\"240,68 340,72 340,80 240,80\" fill=\"#bae6fd\"/>\n  <polygon points=\"120,52 138,52 134,96 120,96\" fill=\"#94a3b8\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"129\" y=\"46\" text-anchor=\"middle\" font-size=\"7\" fill=\"#475569\">diversion</text>\n  <text x=\"70\" y=\"120\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#075985\">Upstream</text>\n  <text x=\"70\" y=\"132\" text-anchor=\"middle\" font-size=\"7\" fill=\"#166534\">takes more →</text>\n  <text x=\"185\" y=\"120\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#0369a1\">Midstream</text>\n  <text x=\"185\" y=\"132\" text-anchor=\"middle\" font-size=\"7\" fill=\"#854d0e\">less arrives</text>\n  <text x=\"295\" y=\"120\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#1e3a8a\">Downstream</text>\n  <text x=\"295\" y=\"132\" text-anchor=\"middle\" font-size=\"7\" fill=\"#991b1b\">least of all</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'tutor_message', $lj${"text":"Disputes like this are exactly why we need **integrated water resources management** — planning a river's *whole basin* together, rather than state by state.\n\nManage the basin as one system, and the many uses and many users can be *balanced* instead of fighting over every drop.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"On the farming side, the **Pradhan Mantri Krishi Sinchayee Yojana (PMKSY)** aims to bring *protective irrigation* to every farm. Two slogans capture it:\n\n- *\"har khet ko pani\"* — water to every field\n- *\"per drop more crop\"* — grow more harvest from less water\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"PMKSY's goals follow from those slogans: expand the area under *assured* irrigation, improve on-farm water-use **efficiency** to cut waste, and build in *sustainable conservation* practices.\n\nUse less, grow more, share fairly. That's the whole philosophy in one line.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'html_animation', $lj${"title":"ONE RIVER, MANY NEIGHBOURS","caption":"When the upstream bucket fills first, the downstream buckets run low.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoUp { 0%,10%{height:6px} 50%,100%{height:34px} }\n    @keyframes geoMid { 0%,30%{height:4px} 70%,100%{height:20px} }\n    @keyframes geoLow { 0%,50%{height:3px} 90%,100%{height:10px} }\n    .geo-up{animation:geoUp 5s ease-in-out infinite alternate} .geo-mid{animation:geoMid 5s ease-in-out infinite alternate} .geo-low{animation:geoLow 5s ease-in-out infinite alternate}\n  </style>\n  <svg viewBox=\"0 0 300 100\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <rect x=\"40\" y=\"20\" width=\"50\" height=\"60\" rx=\"4\" fill=\"none\" stroke=\"#475569\" stroke-width=\"2\"/>\n    <rect class=\"geo-up\" x=\"44\" y=\"46\" width=\"42\" height=\"34\" fill=\"#0ea5e9\"/>\n    <rect x=\"125\" y=\"20\" width=\"50\" height=\"60\" rx=\"4\" fill=\"none\" stroke=\"#475569\" stroke-width=\"2\"/>\n    <rect class=\"geo-mid\" x=\"129\" y=\"60\" width=\"42\" height=\"20\" fill=\"#38bdf8\"/>\n    <rect x=\"210\" y=\"20\" width=\"50\" height=\"60\" rx=\"4\" fill=\"none\" stroke=\"#475569\" stroke-width=\"2\"/>\n    <rect class=\"geo-low\" x=\"214\" y=\"70\" width=\"42\" height=\"10\" fill=\"#7dd3fc\"/>\n    <text x=\"65\" y=\"94\" text-anchor=\"middle\" font-size=\"7\" fill=\"#075985\">upstream</text>\n    <text x=\"150\" y=\"94\" text-anchor=\"middle\" font-size=\"7\" fill=\"#0369a1\">midstream</text>\n    <text x=\"235\" y=\"94\" text-anchor=\"middle\" font-size=\"7\" fill=\"#1e3a8a\">downstream</text>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'mcq', $lj${"question":"Why do inter-state water disputes like the Krishna-Godavari dispute arise?","options":[{"id":"a","text":"Because rivers dry up completely at state borders.","is_correct":false,"rationale":"Rivers cross borders freely — they don't dry up at them. The dispute is about how the shared flow is divided."},{"id":"b","text":"Because a river crosses several states, and an upstream state taking more water leaves less for those downstream.","is_correct":true,"rationale":"Exactly. Upstream diversion (like Maharashtra at Koyna) reduces downstream flow into Karnataka and Andhra Pradesh."},{"id":"c","text":"Because each state builds its own separate river.","is_correct":false,"rationale":"States share the *same* river — that's the whole problem. They can't each have a separate one."},{"id":"d","text":"Because downstream states use no water at all.","is_correct":false,"rationale":"Downstream states rely heavily on the water — which is exactly why they object to losing it."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 10, 'tap_to_match', $lj${"prompt":"Match each term to what it means.","left":[{"id":"l1","label":"Krishna-Godavari dispute"},{"id":"l2","label":"Har khet ko pani"},{"id":"l3","label":"Per drop more crop"},{"id":"l4","label":"Integrated water management"}],"right":[{"id":"r1","label":"States arguing over diversion at Koyna"},{"id":"r2","label":"Water to every field"},{"id":"r3","label":"More harvest from less water"},{"id":"r4","label":"Planning a river's whole basin together"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'exercise', $lj${"instruction":"Inter-state water disputes are common in India. Try to name one (the Krishna-Godavari is one; the Cauvery is another famous one).\n\nOn paper, write which states are involved and what they're arguing over. Type the dispute and the states below.\n","tool":"pencil","placeholder":"The ___ dispute, between the states of..."}$lj$::jsonb, 15, true),
    (v_lesson, 12, 'fill_in_the_blank', $lj${"prompt":"Lock in the sharing problem and the fix.","template":"When a river crosses states, taking more water upstream cuts the {{blank-1}} flow; PMKSY's slogan 'per drop more {{blank-2}}' pushes water-use efficiency.\n","answers":[{"id":"blank-1","accepted":["downstream","down-stream","Downstream"]},{"id":"blank-2","accepted":["crop","Crop"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 13, 'reflection', $lj${"prompt":"No state *owns* a river that flows through many — yet each acts as if its stretch is its own. What would it take for states to truly treat a shared river as shared?\n\nNo right answer.\n","placeholder":"For states to share a river fairly, it would take..."}$lj$::jsonb, 5, true),
    (v_lesson, 14, 'checkpoint', $lj${"title":"You can explain why rivers cause disputes — and how to share them.","summary":"A river crossing many states sparks disputes, because upstream use cuts downstream flow — like Krishna-Godavari. The answers: integrated basin-wide management, and on the farm, PMKSY's \"har khet ko pani\" and \"per drop more crop\".\n\nBut big dams and shared rivers aren't the only way to secure water. There's a far older, far smaller idea — one that doesn't dam a river or fight a neighbour. It just catches the rain where it falls. That's the final course.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Three-quarters of the planet is covered in water. And it recycles itself — *forever*.\n\nSo here's a puzzle that should stop you: how can we possibly **run out**?\n\nBy the end of this lesson, the puzzle will bother you more, not less. Good.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"Start with the numbers. Yes, three-fourths of Earth's surface is water — but only a *tiny* slice of it is **freshwater** we can actually use.\n\nThat usable freshwater comes from two places: **surface run-off** (rivers, streams) and **groundwater** (water stored under the ground).\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"And it is genuinely **renewable**. The **hydrological cycle** — the water cycle — constantly renews and recharges it.\n\nWater evaporates, forms clouds, falls as rain, flows across the land and soaks into the ground, then evaporates again. The machine never stops turning.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch03-water-resources/c1l1-water-cycle.png","caption":"The water cycle: the same water evaporates and rains down, used again and again — which is exactly why it *feels* endless.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'svg_graphic', $lj${"title":"THE HYDROLOGICAL CYCLE","caption":"Evaporation, rain, run-off, and recharge — the cycle that makes water a renewable resource.","svg":"<svg viewBox=\"0 0 360 200\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"0\" y=\"160\" width=\"360\" height=\"40\" fill=\"#bae6fd\"/>\n  <circle cx=\"40\" cy=\"36\" r=\"20\" fill=\"#fde68a\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <ellipse cx=\"180\" cy=\"44\" rx=\"46\" ry=\"22\" fill=\"#e2e8f0\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"180\" y=\"48\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">cloud</text>\n  <path d=\"M70,158 C90,110 110,80 138,56\" stroke=\"#0ea5e9\" stroke-width=\"2\" fill=\"none\"/>\n  <polygon points=\"138,56 132,66 144,66\" fill=\"#0ea5e9\"/>\n  <text x=\"88\" y=\"120\" font-size=\"8\" fill=\"#0369a1\">evaporation</text>\n  <line x1=\"200\" y1=\"66\" x2=\"205\" y2=\"150\" stroke=\"#2563eb\" stroke-width=\"1.5\" stroke-dasharray=\"3 3\"/>\n  <line x1=\"220\" y1=\"66\" x2=\"228\" y2=\"150\" stroke=\"#2563eb\" stroke-width=\"1.5\" stroke-dasharray=\"3 3\"/>\n  <line x1=\"240\" y1=\"66\" x2=\"251\" y2=\"150\" stroke=\"#2563eb\" stroke-width=\"1.5\" stroke-dasharray=\"3 3\"/>\n  <text x=\"262\" y=\"110\" font-size=\"8\" fill=\"#1e3a8a\">precipitation</text>\n  <polygon points=\"300,160 360,160 360,120\" fill=\"#bbf7d0\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n  <path d=\"M330,128 C320,140 318,150 300,160\" stroke=\"#0ea5e9\" stroke-width=\"2\" fill=\"none\"/>\n  <text x=\"300\" y=\"150\" font-size=\"8\" fill=\"#166534\">run-off</text>\n  <text x=\"40\" y=\"186\" font-size=\"8\" fill=\"#0c4a6e\">surface water + groundwater</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"So here's the puzzle in full.\n\nIf water is everywhere *and* renews itself, why do regions all over the world suffer **water scarcity**? Why is it predicted that by **2025**, nearly **two billion** people will live in *absolute* water scarcity?\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"Your gut probably jumps to deserts — low-rainfall Rajasthan, women walking miles balancing *matkas* of water.\n\nAnd it's *partly* true: water availability does vary over space and time, mostly because rainfall varies by season and year. But hold on — that's **not** the main reason for scarcity.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'tutor_message', $lj${"text":"Here's the twist that runs through this whole chapter.\n\nScarcity is mostly caused not by *too little rain*, but by **us**: over-exploitation, excessive use, and unequal access. A region can be *soaked* in water and *still* be scarce.\n\n*What would break if rainfall alone explained scarcity?* Then no rainy city would ever run dry. Many do.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'html_animation', $lj${"title":"THE CYCLE NEVER STOPS","caption":"One drop, going round and round — renewable in theory, if we don't drain it faster than it returns.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoLoop { 0%{offset-distance:0%} 100%{offset-distance:100%} }\n    .geo-drop { offset-path: path('M 40,110 C 60,40 150,30 175,55 C 200,80 210,100 250,110'); animation: geoLoop 4s linear infinite; }\n  </style>\n  <svg viewBox=\"0 0 300 130\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <rect x=\"0\" y=\"108\" width=\"300\" height=\"22\" fill=\"#bae6fd\"/>\n    <ellipse cx=\"160\" cy=\"40\" rx=\"36\" ry=\"16\" fill=\"#e2e8f0\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <path d=\"M 40,110 C 60,40 150,30 175,55 C 200,80 210,100 250,110\" stroke=\"#cbd5e1\" stroke-width=\"1.5\" fill=\"none\" stroke-dasharray=\"3 3\"/>\n    <circle r=\"6\" fill=\"#2563eb\" class=\"geo-drop\"/>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'mcq', $lj${"question":"What makes water a renewable resource?","options":[{"id":"a","text":"There is simply so much of it that it can never run out.","is_correct":false,"rationale":"Most of Earth's water isn't usable freshwater — and we *can* run short. Sheer quantity isn't what 'renewable' means here."},{"id":"b","text":"The hydrological cycle constantly renews and recharges surface water and groundwater.","is_correct":true,"rationale":"Right. Evaporation, rain, run-off, and recharge keep cycling water back to us — that's what makes it renewable."},{"id":"c","text":"Factories manufacture fresh water to replace what we use.","is_correct":false,"rationale":"Fresh water isn't manufactured at scale. It's renewed by nature's water cycle."},{"id":"d","text":"Because it never evaporates, so none is ever lost.","is_correct":false,"rationale":"The opposite — evaporation is a *key step* of the cycle that renews water."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'drag_to_reorder', $lj${"prompt":"Put the stages of the water cycle in order, starting from the sea.","items":[{"id":"s1","label":"Evaporation — water rises from the sea"},{"id":"s2","label":"Condensation — clouds form"},{"id":"s3","label":"Precipitation — rain falls"},{"id":"s4","label":"Run-off and recharge — water flows back and soaks in"}],"correct_order":["s1","s2","s3","s4"]}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'exercise', $lj${"instruction":"Where does the water in your tap actually come from — a river, a reservoir, a borewell (groundwater), rainwater?\n\nOn paper, trace it back one step at a time to the rain that started it. Type your water's source below.\n","tool":"pencil","placeholder":"My water comes from ___, which is fed by..."}$lj$::jsonb, 15, true),
    (v_lesson, 13, 'fill_in_the_blank', $lj${"prompt":"Lock in the paradox.","template":"Water is renewable because the {{blank-1}} cycle constantly renews it — yet by the year {{blank-2}}, nearly two billion people may face absolute scarcity.\n","answers":[{"id":"blank-1","accepted":["hydrological","water","Hydrological"]},{"id":"blank-2","accepted":["2025"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 14, 'reflection', $lj${"prompt":"You probably treat tap water as endless — turn it on, it's there. After this lesson, does \"renewable\" feel like a comfort or a warning? Why?\n\nNo right answer.\n","placeholder":"'Renewable' now feels like..."}$lj$::jsonb, 5, true),
    (v_lesson, 15, 'checkpoint', $lj${"title":"You can explain why water is renewable — and still scarce.","summary":"Water covers most of the planet and the hydrological cycle renews it endlessly, yet two billion people may face absolute scarcity by 2025. The reason isn't only rainfall — it's how we use and share what we have.\n\nSo let's name the real culprits. Why does even a well-watered country end up running dry? That's the next lesson.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Here's something that shouldn't be possible: a city sitting right beside a river, and *still* short of water.\n\nYet many of our cities are exactly that. If rain isn't the problem, what is?\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"Water scarcity has three root causes — and notice that *none* of them is \"not enough rain\":\n\n- **over-exploitation**\n- **excessive use**\n- **unequal access**\n\nLet's see how each one drains a country that's actually quite wet.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"**Cause 1 — a growing population.**\n\nMore people need more water — not just to drink, but to grow more *food*. To boost food-grain production, we over-exploit water to expand irrigation for dry-season farming.\n\nAnd **irrigated agriculture is the single largest consumer of water** in India. The crowd at the well keeps getting bigger.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch03-water-resources/c1l2-thirsty-city.png","caption":"A city right beside a river, yet the ground in front of it runs cracked and dry — the paradox of a wet place still short of water.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'svg_graphic', $lj${"title":"WHO USES THE WATER","caption":"From one finite freshwater supply — agriculture takes the largest share, by far.","svg":"<svg viewBox=\"0 0 360 170\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"120\" y=\"8\" width=\"120\" height=\"26\" rx=\"5\" fill=\"#0ea5e9\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"180\" y=\"25\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#ffffff\">FRESHWATER</text>\n  <line x1=\"180\" y1=\"34\" x2=\"70\" y2=\"64\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n  <line x1=\"180\" y1=\"34\" x2=\"180\" y2=\"64\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n  <line x1=\"180\" y1=\"34\" x2=\"290\" y2=\"64\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n  <rect x=\"26\" y=\"64\" width=\"88\" height=\"92\" rx=\"5\" fill=\"#bbf7d0\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"70\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#166534\">Agriculture</text>\n  <text x=\"70\" y=\"100\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">largest</text>\n  <text x=\"70\" y=\"111\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">consumer</text>\n  <rect x=\"136\" y=\"96\" width=\"88\" height=\"60\" rx=\"5\" fill=\"#fde68a\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"180\" y=\"120\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#92400e\">Industry</text>\n  <rect x=\"246\" y=\"104\" width=\"88\" height=\"52\" rx=\"5\" fill=\"#e9d5ff\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"290\" y=\"128\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#6b21a8\">Homes</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"**Cause 2 — the groundwater trap.**\n\nFarmers dig their own wells and tube-wells to irrigate more land. It sounds smart — until you realise everyone is doing it.\n\nPump too much, and **groundwater levels fall**. That hurts water availability *and* food security down the line. A short-term win that becomes a long-term loss.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"**Cause 3 — industries and cities.**\n\nAfter Independence, rapid industrialisation and urbanisation. Industries are heavy water users — *and* they need power, much of it **hydroelectric**, so even electricity quietly costs water.\n\nDense cities and urban lifestyles pile on demand. Housing societies sink their own borewells. The result: fragile water resources over-exploited until they're depleted.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'html_animation', $lj${"title":"A BIGGER CROWD AT THE WELL","caption":"More people, more farms, more factories — all drinking from the same shrinking supply.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoDrop { 0%,15%{height:60px;fill:#0ea5e9} 85%,100%{height:18px;fill:#7dd3fc} }\n    @keyframes geoFade1 { 0%,10%{opacity:0} 30%,100%{opacity:1} }\n    @keyframes geoFade2 { 0%,35%{opacity:0} 55%,100%{opacity:1} }\n    @keyframes geoFade3 { 0%,60%{opacity:0} 80%,100%{opacity:1} }\n    .geo-w { animation: geoDrop 5s ease-in-out infinite alternate; }\n    .gf1{animation:geoFade1 5s infinite} .gf2{animation:geoFade2 5s infinite} .gf3{animation:geoFade3 5s infinite}\n  </style>\n  <svg viewBox=\"0 0 300 120\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <rect x=\"130\" y=\"40\" width=\"40\" height=\"60\" fill=\"#0ea5e9\" class=\"geo-w\"/>\n    <rect x=\"124\" y=\"34\" width=\"52\" height=\"8\" rx=\"3\" fill=\"#475569\"/>\n    <circle class=\"gf1\" cx=\"60\" cy=\"60\" r=\"12\" fill=\"#16a34a\"/>\n    <circle class=\"gf2\" cx=\"60\" cy=\"92\" r=\"12\" fill=\"#ca8a04\"/>\n    <circle class=\"gf3\" cx=\"240\" cy=\"76\" r=\"12\" fill=\"#7c3aed\"/>\n    <text x=\"150\" y=\"115\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0369a1\">the well drops as the crowd grows</text>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'tutor_message', $lj${"text":"Look back at all three causes. Not one of them is about *rainfall*.\n\nIt's **demand** outrunning the renewable supply — plus **unequal access**, where some get plenty and others get almost none. That's how a wet country runs dry.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'mcq', $lj${"question":"What is the single largest consumer of water in India?","options":[{"id":"a","text":"Household / domestic use.","is_correct":false,"rationale":"Homes use water, but their share is far smaller than the biggest consumer."},{"id":"b","text":"Irrigated agriculture.","is_correct":true,"rationale":"Correct — irrigated agriculture is by far the largest consumer, which is why expanding irrigation over-exploits water."},{"id":"c","text":"Hydroelectric power stations.","is_correct":false,"rationale":"Industry and power do use a lot of water, but irrigated agriculture is the largest consumer overall."},{"id":"d","text":"Drinking water for cattle.","is_correct":false,"rationale":"A real use, but tiny compared with irrigated agriculture."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'tap_to_match', $lj${"prompt":"Match each cause of scarcity to what it leads to.","left":[{"id":"l1","label":"A growing population"},{"id":"l2","label":"Farmers over-pumping wells"},{"id":"l3","label":"More industries"},{"id":"l4","label":"Dense cities with their own borewells"}],"right":[{"id":"r1","label":"More food needed → more irrigation"},{"id":"r2","label":"Falling groundwater levels"},{"id":"r3","label":"Heavy water use plus demand for hydel power"},{"id":"r4","label":"Over-exploited, depleted local water"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'exercise', $lj${"instruction":"List every way your household used water *today* — drinking, cooking, bathing, washing, the garden, flushing.\n\nOn paper, mark which one used the most. Then type your single biggest household water use below.\n","tool":"pencil","placeholder":"My household's biggest water use is..."}$lj$::jsonb, 15, true),
    (v_lesson, 13, 'fill_in_the_blank', $lj${"prompt":"Lock in the two big drains.","template":"Irrigated {{blank-1}} is the largest consumer of water, and over-pumping wells makes {{blank-2}} levels fall.\n","answers":[{"id":"blank-1","accepted":["agriculture","Agriculture","farming"]},{"id":"blank-2","accepted":["groundwater","ground water","Groundwater"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 14, 'reflection', $lj${"prompt":"Every farmer digging a deeper well is acting sensibly for *themselves* — but together they drain the shared groundwater. Where else in life do many sensible individual choices add up to a shared problem?\n\nNo right answer.\n","placeholder":"Many small choices adding up to a big problem — like..."}$lj$::jsonb, 5, true),
    (v_lesson, 15, 'checkpoint', $lj${"title":"You can name why demand, not rain, drives water scarcity.","summary":"Over-exploitation for irrigation (the biggest user), falling groundwater from too many wells, and the thirst of industries and cities — demand outruns the renewable supply, and access stays unequal. Rainfall is barely the point.\n\nBut there's one more kind of scarcity, and it's sneaky: water that's *right there* but unsafe to drink. What happens when the problem isn't quantity, but quality? That's the next lesson.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Picture a glass of water, full to the very brim. Now imagine you can't drink a single drop of it.\n\nThat's the *third* kind of water scarcity — and it has nothing to do with how much water there is.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"So far we've counted *quantity* scarcity — not enough water.\n\nBut a region can have **plenty** of water and *still* suffer scarcity, for a different reason: the water is **bad quality**. Enough to fill every glass, but unsafe to use.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"What poisons it?\n\n**Domestic and industrial wastes**, and the **chemicals, pesticides, and fertilisers** that wash off our farms. They make otherwise-ample water *hazardous* for human use.\n\nLots of water. None you'd want to drink.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch03-water-resources/c1l3-polluted-water.png","caption":"Plenty of water — but cloudy, polluted, unsafe. Scarcity is about *quality*, not just quantity.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'svg_graphic', $lj${"title":"TWO KINDS OF SCARCITY","caption":"Quantity scarcity (no water) — and quality scarcity (plenty of water, but unsafe).","svg":"<svg viewBox=\"0 0 360 170\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"20\" y=\"14\" width=\"150\" height=\"142\" rx=\"8\" fill=\"#f8fafc\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"95\" y=\"34\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#0f172a\">Quantity</text>\n  <rect x=\"72\" y=\"70\" width=\"46\" height=\"64\" rx=\"4\" fill=\"#f1f5f9\" stroke=\"#475569\" stroke-width=\"2\"/>\n  <text x=\"95\" y=\"150\" text-anchor=\"middle\" font-size=\"8\" fill=\"#991b1b\">empty — too little water</text>\n  <rect x=\"190\" y=\"14\" width=\"150\" height=\"142\" rx=\"8\" fill=\"#f8fafc\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"265\" y=\"34\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#0f172a\">Quality</text>\n  <rect x=\"242\" y=\"70\" width=\"46\" height=\"64\" rx=\"4\" fill=\"#84cc16\" stroke=\"#475569\" stroke-width=\"2\" opacity=\"0.55\"/>\n  <circle cx=\"255\" cy=\"92\" r=\"3\" fill=\"#3f6212\"/><circle cx=\"276\" cy=\"104\" r=\"3\" fill=\"#3f6212\"/><circle cx=\"263\" cy=\"118\" r=\"3\" fill=\"#3f6212\"/>\n  <text x=\"265\" y=\"150\" text-anchor=\"middle\" font-size=\"8\" fill=\"#854d0e\">full — but polluted</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"So what is India doing about it?\n\nFirst, the **Jal Jeevan Mission (JJM)**. Its goal: give *every rural household* assured, potable **piped water** — 55 litres per person per day, reliably, for the long term.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"Second, **Atal Bhujal Yojana (Atal Jal)** — aimed at *groundwater*, running across 8,220 *water-stressed* Gram Panchayats.\n\nIts key idea isn't only pipes and pumps. It's **behavioural change** — shifting whole communities from an attitude of *consumption* to one of *conservation*.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'html_animation', $lj${"title":"FULL, BUT NOT FIT TO DRINK","caption":"The glass fills right up — and then the pollution creeps in. Quantity is only half the battle.","html":"<div style=\"background:#f0f9ff;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoFillUp { 0%,10%{height:0} 45%,100%{height:70px} }\n    @keyframes geoPollute { 0%,50%{fill:#38bdf8} 90%,100%{fill:#84cc16} }\n    .geo-fill { animation: geoFillUp 5s ease-in-out infinite alternate, geoPollute 5s ease-in-out infinite alternate; }\n  </style>\n  <svg viewBox=\"0 0 200 120\" style=\"max-width:200px;width:100%\" font-family=\"sans-serif\">\n    <rect x=\"78\" y=\"22\" width=\"44\" height=\"76\" rx=\"4\" fill=\"none\" stroke=\"#475569\" stroke-width=\"2.5\"/>\n    <rect x=\"80\" y=\"28\" width=\"40\" height=\"70\" class=\"geo-fill\" />\n    <text x=\"100\" y=\"114\" text-anchor=\"middle\" font-size=\"8\" fill=\"#0369a1\">full glass, unsafe water</text>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'tutor_message', $lj${"text":"Why does all of this matter so much?\n\nConserving and managing water protects our **health**, our **food security**, our **livelihoods**, and our **ecosystems**. Over-exploit and mismanage it, and you trigger an *ecological crisis* that hits every one of those at once.\n\nWater isn't just a resource. It's the thread all of them hang from.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'mcq', $lj${"question":"A region gets high annual rainfall, but its water is heavily polluted. Is it suffering from water scarcity?","options":[{"id":"a","text":"No — high rainfall means there's plenty of water, so no scarcity.","is_correct":false,"rationale":"Quantity isn't the only thing that matters. Polluted water is unsafe to use, so the region IS scarce."},{"id":"b","text":"Yes — water you can't safely use is a form of scarcity (quality scarcity).","is_correct":true,"rationale":"Right. Ample but polluted water still leaves people without usable water — that's scarcity of *quality*."},{"id":"c","text":"Only if the rainfall later decreases.","is_correct":false,"rationale":"The region is already scarce *now* — the water present is unusable, regardless of future rainfall."},{"id":"d","text":"No — pollution is a separate problem, not scarcity.","is_correct":false,"rationale":"Pollution directly causes scarcity by making available water unsafe to use."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'tap_to_match', $lj${"prompt":"Match each term to what it means.","left":[{"id":"l1","label":"Jal Jeevan Mission"},{"id":"l2","label":"Atal Bhujal Yojana"},{"id":"l3","label":"Quality scarcity"},{"id":"l4","label":"Main water pollutants"}],"right":[{"id":"r1","label":"55 litres of piped potable water to every rural home"},{"id":"r2","label":"Groundwater — shifting from consumption to conservation"},{"id":"r3","label":"Enough water, but too polluted to use safely"},{"id":"r4","label":"Wastes, chemicals, pesticides, and fertilisers"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'exercise', $lj${"instruction":"Write a short proposal (4–5 lines) on how *you* could conserve water in your daily life — at the tap, in the bathroom, in the kitchen, in the garden.\n\nPick the one change that would save the most, and type it below.\n","tool":"pencil","placeholder":"My biggest water-saving change would be..."}$lj$::jsonb, 15, true),
    (v_lesson, 13, 'fill_in_the_blank', $lj${"prompt":"Lock in quality scarcity and the mission.","template":"Scarcity can come from bad water {{blank-1}} when wastes and chemicals pollute it; the {{blank-2}} Jeevan Mission delivers piped potable water to rural homes.\n","answers":[{"id":"blank-1","accepted":["quality","Quality"]},{"id":"blank-2","accepted":["Jal","jal"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 14, 'reflection', $lj${"prompt":"Atal Jal bets that the real fix is *behaviour* — getting people to value conservation, not just building more infrastructure. Do you think changing habits is harder or easier than building dams and pipes? Why?\n\nNo right answer.\n","placeholder":"Changing habits versus building things — I think..."}$lj$::jsonb, 5, true),
    (v_lesson, 15, 'checkpoint', $lj${"title":"You understand scarcity of quantity AND quality — and how India is fighting both.","summary":"Water can be scarce not only when there's too little, but when what's there is too polluted to use. Jal Jeevan Mission brings piped potable water to rural homes; Atal Jal tackles groundwater by shifting communities from consumption to conservation. The stakes: health, food, livelihoods, ecosystems.\n\nBut all of this raises one practical question we've dodged so far: *how* do we actually store and manage water at scale? For most of the last century, India's big answer was a single, towering structure — the dam. That's where the next course begins.\n","xp":0}$lj$::jsonb, 0, true);
